22→    public IssueTemplate create(int templateId, String fields, Integer orderNo, Integer parentIssueTemplateId, String upstreamIssueTemplateIds) {
23→        String safeFields = fields == null ? "" : fields;
24→        String ids = (upstreamIssueTemplateIds == null) ? "" : upstreamIssueTemplateIds.trim();
25→        return ao.create(IssueTemplate.class,
26→                new DBParam("TEMPLATE_ID", templateId),
27→                new DBParam("FIELDS", safeFields),
28→                new DBParam("UPSTREAM_ISSUE_TEMPLATE_ID", 0),
29→                new DBParam("UPSTREAM_ISSUE_TEMPLATE_IDS", ids),
30→                new DBParam("PARENT_ISSUE_TEMPLATE_ID", parentIssueTemplateId == null ? 0 : parentIssueTemplateId),
31→                new DBParam("ORDER_NO", orderNo == null ? 0 : orderNo));
32→    }
33→
34→    public IssueTemplate update(int id, String fields, Integer parentIssueTemplateId, String upstreamIssueTemplateIds) {
35→        IssueTemplate it = ao.get(IssueTemplate.class, id);
36→        if (it == null) return null;
37→        it.setFields(fields == null ? "" : fields);
38→        it.setUpstreamIssueTemplateIds(upstreamIssueTemplateIds == null ? "" : upstreamIssueTemplateIds.trim());
39→        it.setUpstreamIssueTemplateId(0);
40→        it.setParentIssueTemplateId(parentIssueTemplateId == null ? 0 : parentIssueTemplateId);
41→        it.save();
42→        return it;
43→    }
44→
45→    public boolean deleteById(int id) {
46→        IssueTemplate it = ao.get(IssueTemplate.class, id);
47→        if (it == null) return false;
48→        ao.delete(it);
49→        return true;
50→    }
51→
52→    public IssueTemplate[] listByTemplateId(int templateId) {
53→        return ao.find(IssueTemplate.class, Query.select().where("TEMPLATE_ID = ?", templateId));
54→    }
55→
56→    public IssueTemplate getById(int id) {
57→        return ao.get(IssueTemplate.class, id);
58→    }
59→
60→    public int getMaxOrderNoByTemplateId(int templateId) {
61→        IssueTemplate[] arr = ao.find(IssueTemplate.class, Query.select().where("TEMPLATE_ID = ?", templateId));
62→        int max = 0;
63→        for (IssueTemplate it : arr) max = Math.max(max, it.getOrderNo());
64→        return max;
65→    }
66→}

