251→    private TemplateGroupVo createTemplateGroup(HttpServletRequest request) throws Exception {
252→        UserProfile user = userManager.getRemoteUser(request);
253→        if (user == null) throw new RuntimeException("未登录");
254→
255→        TemplateGroupCreateRo ro = readJsonBody(request, TemplateGroupCreateRo.class);
256→        if (ro == null || ro.getName() == null || ro.getName().trim().isEmpty()) {
257→            throw new RuntimeException("名称不能为空");
258→        }
259→        TemplateGroup created = templateGroupMapper.create(ro.getName().trim());
260→        return TemplateGroupVo.from(created);
