 16→ */
 17→var _contextPath = '';  // 私有变量存储contextPath
 18→
 19→function getContextPath() {
 20→    // 如果已经设置了上下文路径，直接返回
 21→    if (_contextPath !== undefined && _contextPath !== null && _contextPath !== '') {
 22→        console.log("使用已设置的上下文路径: " + _contextPath);
 23→        return _contextPath;
 24→    }
 25→    
 26→    // 尝试从页面URL中获取上下文路径
 27→    try {
 28→        // 获取当前页面URL的路径部分
 29→        var pathName = window.location.pathname;
 30→        console.log("当前页面路径: " + pathName);
 31→        
 32→        // 检查路径中是否包含/jira前缀
 33→        var jiraIndex = pathName.indexOf('/jira');
 34→        if (jiraIndex === 0) {
 35→            _contextPath = '/jira';
 36→            console.log("从URL检测到上下文路径: " + _contextPath);
 37→            return _contextPath;
 38→        }
 39→        
 40→        // 尝试从AJS.contextPath()获取，如果可用
 41→        if (typeof AJS !== 'undefined' && typeof AJS.contextPath === 'function') {
 42→            var ajsContextPath = AJS.contextPath();
 43→            if (ajsContextPath) {
 44→                _contextPath = ajsContextPath;
 45→                console.log("从AJS.contextPath()获取到上下文路径: " + _contextPath);
 46→                return _contextPath;
 47→            }
 48→        }
 49→        
 50→        // 尝试从meta标签获取
 51→        var metaContextPath = document.querySelector('meta[name="ajs-context-path"]');
 52→        if (metaContextPath) {
 53→            _contextPath = metaContextPath.getAttribute('content') || '';
 54→            console.log("从meta标签获取到上下文路径: " + _contextPath);
 55→            return _contextPath;
 56→        }
 57→    } catch(e) {
 58→        console.error("获取上下文路径时出错: ", e);
 59→    }
 60→    
 61→    // 默认返回空字符串（用于生产环境）
 62→    console.log("未能检测到上下文路径，使用默认值: ''");
 63→    return '';
 64→}
