  3→import lombok.extern.slf4j.Slf4j;
  4→import org.json.JSONArray;
  5→import org.json.JSONObject;
  6→
  7→import javax.servlet.http.HttpServletRequest;
  8→import javax.servlet.http.HttpServletResponse;
  9→import java.beans.Introspector;
 10→import java.beans.PropertyDescriptor;
 11→import java.io.BufferedReader;
 12→import java.io.IOException;
 13→import java.io.PrintWriter;
 14→import java.lang.reflect.Method;
 15→import java.lang.reflect.Modifier;
 16→import java.lang.reflect.ParameterizedType;
 17→import java.lang.reflect.Type;
 18→import java.util.*;
 19→import java.util.function.BiConsumer;
 20→
 21→@Slf4j
 22→public final class HttpJsonSupport {
 23→
 24→    private HttpJsonSupport() {}
 25→
 26→    @FunctionalInterface
 27→    public interface JsonRequestHandler<T> {
 28→        T handle(HttpServletRequest request) throws Exception;
 29→    }
 30→
 31→    public static <T> BiConsumer<HttpServletRequest, HttpServletResponse> jsonEndpoint(JsonRequestHandler<T> handler) {
 32→        return (request, response) -> {
 33→            response.setContentType("application/json;charset=UTF-8");
 34→            try {
 35→                T result = handler.handle(request);
 36→                ResponseData<T> wrapped = ResponseData.success(result);
 37→                String json = toJsonString(wrapped);
 38→                PrintWriter out = response.getWriter();
 39→                out.print(json);
 40→                out.flush();
 41→            } catch (Throwable e) {
 42→                try {
 43→                    ResponseData<Void> error = ResponseData.error(e.getMessage());
 44→                    String json = toJsonString(error);
 45→                    PrintWriter out = response.getWriter();
 46→                    out.print(json);
 47→                    out.flush();
 48→                } catch (Exception ignored) {
 49→                }
 50→                log.warn("Error handling JSON endpoint: {}", e.getMessage());
 51→            }
 52→        };
 53→    }
 54→
 55→    public static String toJsonString(ResponseData<?> responseData) {
 56→        JSONObject json = new JSONObject();
 57→        json.put("success", responseData.getSuccess());
 58→        json.put("code", responseData.getCode());
 59→        if (responseData.getMessage() != null) {
 60→            json.put("message", responseData.getMessage());
 61→        }
 62→        json.put("data", toJsonValue(responseData.getData()));
 63→        return json.toString();
 64→    }
 65→
 66→    public static Object toJsonValue(Object data) {
 67→        if (data == null) {
 68→            return JSONObject.NULL;
 69→        }
 70→        if (data instanceof JSONObject || data instanceof JSONArray) {
 71→            return data;
 72→        }
 73→        if (data instanceof CharSequence || data instanceof Number || data instanceof Boolean) {
 74→            return data;
 75→        }
 76→        if (data instanceof Enum) {
 77→            return ((Enum<?>) data).name();
 78→        }
 79→        if (data instanceof Map) {
 80→            JSONObject obj = new JSONObject();
 81→            Map<?, ?> map = (Map<?, ?>) data;
 82→            for (Map.Entry<?, ?> entry : map.entrySet()) {
 83→                Object key = entry.getKey();
 84→                if (key != null) {
 85→                    obj.put(String.valueOf(key), toJsonValue(entry.getValue()));
 86→                }
 87→            }
 88→            return obj;
 89→        }
 90→        if (data instanceof Collection) {
 91→            JSONArray arr = new JSONArray();
 92→            for (Object item : (Collection<?>) data) {
 93→                arr.put(toJsonValue(item));
 94→            }
 95→            return arr;
 96→        }
 97→        if (data.getClass().isArray()) {
 98→            JSONArray arr = new JSONArray();
 99→            int length = java.lang.reflect.Array.getLength(data);
100→            for (int i = 0; i < length; i++) {
101→                Object item = java.lang.reflect.Array.get(data, i);
102→                arr.put(toJsonValue(item));
103→            }
104→            return arr;
105→        }
106→        // Try JavaBean via Introspector
107→        try {
108→            JSONObject obj = new JSONObject();
109→            for (PropertyDescriptor pd : Introspector.getBeanInfo(data.getClass(), Object.class).getPropertyDescriptors()) {
110→                Method readMethod = pd.getReadMethod();
111→                if (readMethod == null) {
112→                    continue;
113→                }
114→                try { readMethod.setAccessible(true); } catch (Exception ignored) {}
115→                Object value = readMethod.invoke(data);
116→                obj.put(pd.getName(), toJsonValue(value));
117→            }
118→            if (obj.length() > 0) {
119→                return obj;
120→            }
121→        } catch (Exception ignored) {
122→        }
123→        // Fallback: scan public getters
124→        try {
125→            JSONObject obj = new JSONObject();
126→            Method[] methods = data.getClass().getMethods();
127→            for (Method m : methods) {
128→                if (m.getParameterCount() != 0) continue;
129→                if (!Modifier.isPublic(m.getModifiers())) continue;
130→                String name = m.getName();
131→                if (name.equals("getClass")) continue;
132→                if (name.startsWith("get") && name.length() > 3) {
133→                    String prop = Character.toLowerCase(name.charAt(3)) + name.substring(4);
134→                    Object value = m.invoke(data);
135→                    obj.put(prop, toJsonValue(value));
136→                } else if (name.startsWith("is") && name.length() > 2) {
137→                    String prop = Character.toLowerCase(name.charAt(2)) + name.substring(3);
138→                    Object value = m.invoke(data);
139→                    obj.put(prop, toJsonValue(value));
140→                }
141→            }
142→            if (obj.length() > 0) {
143→                return obj;
144→            }
145→        } catch (Exception ignored) {
146→        }
147→        // Last resort: string
148→        return String.valueOf(data);
149→    }
150→
151→    public static <T> T readJsonBody(HttpServletRequest request, Class<T> type) throws Exception {
152→        String body = readBody(request);
153→        if (body == null || body.trim().isEmpty()) {
154→            throw new RuntimeException("请求体不能为空");
155→        }
156→        Object json;
157→        char first = body.trim().charAt(0);
158→        if (first == '{') {
159→            json = new JSONObject(body);
160→        } else if (first == '[') {
161→            json = new JSONArray(body);
162→        } else {
163→            throw new RuntimeException("请求体必须为JSON");
164→        }
165→        @SuppressWarnings("unchecked")
166→        T result = (T) fromJsonValue(json, type);
167→        return result;
168→    }
169→
170→    public static String readBody(HttpServletRequest request) throws IOException {
171→        StringBuilder sb = new StringBuilder();
172→        try (BufferedReader reader = request.getReader()) {
173→            String line;
174→            while ((line = reader.readLine()) != null) {
175→                sb.append(line);
176→            }
177→        }
178→        return sb.toString();
179→    }
180→
181→    private static Object fromJsonValue(Object jsonVal, Class<?> targetType) throws Exception {
182→        if (jsonVal == null || jsonVal == JSONObject.NULL) {
183→            return null;
184→        }
185→        if (targetType == Object.class) {
186→            if (jsonVal instanceof JSONObject) {
187→                Map<String, Object> map = new HashMap<>();
188→                JSONObject o = (JSONObject) jsonVal;
189→                for (java.util.Iterator<String> it = o.keys(); it.hasNext(); ) { String key = it.next();
190→                    map.put(key, fromJsonValue(o.get(key), Object.class));
191→                }
192→                return map;
193→            }
194→            if (jsonVal instanceof JSONArray) {
195→                JSONArray arr = (JSONArray) jsonVal;
196→                List<Object> list = new ArrayList<>();
197→                for (int i = 0; i < arr.length(); i++) {
198→                    list.add(fromJsonValue(arr.get(i), Object.class));
199→                }
200→                return list;
201→            }
202→            return jsonVal;
203→        }
204→        if (CharSequence.class.isAssignableFrom(targetType)) {
205→            return String.valueOf(jsonVal);
206→        }
207→        if (targetType == Integer.class || targetType == int.class) {
208→            return (jsonVal instanceof Number) ? ((Number) jsonVal).intValue() : Integer.parseInt(String.valueOf(jsonVal));
209→        }
210→        if (targetType == Long.class || targetType == long.class) {
211→            return (jsonVal instanceof Number) ? ((Number) jsonVal).longValue() : Long.parseLong(String.valueOf(jsonVal));
212→        }
213→        if (targetType == Double.class || targetType == double.class) {
214→            return (jsonVal instanceof Number) ? ((Number) jsonVal).doubleValue() : Double.parseDouble(String.valueOf(jsonVal));
215→        }
216→        if (targetType == Float.class || targetType == float.class) {
217→            return (jsonVal instanceof Number) ? ((Number) jsonVal).floatValue() : Float.parseFloat(String.valueOf(jsonVal));
218→        }
219→        if (targetType == Boolean.class || targetType == boolean.class) {
220→            if (jsonVal instanceof Boolean) return jsonVal;
221→            String s = String.valueOf(jsonVal);
222→            return "true".equalsIgnoreCase(s) || "1".equals(s);
223→        }
224→        if (targetType.isEnum()) {
225→            @SuppressWarnings("unchecked")
226→            Class<? extends Enum> enumType = (Class<? extends Enum>) targetType;
227→            return Enum.valueOf(enumType, String.valueOf(jsonVal));
228→        }
229→        if (Map.class.isAssignableFrom(targetType)) {
230→            Map<String, Object> map = new HashMap<>();
231→            JSONObject o = (JSONObject) (jsonVal instanceof JSONObject ? jsonVal : new JSONObject(String.valueOf(jsonVal)));
232→            for (java.util.Iterator<String> it = o.keys(); it.hasNext(); ) { String key = it.next();
233→                map.put(key, fromJsonValue(o.get(key), Object.class));
234→            }
235→            return map;
236→        }
237→        if (Collection.class.isAssignableFrom(targetType)) {
238→            JSONArray arr = (JSONArray) (jsonVal instanceof JSONArray ? jsonVal : new JSONArray(String.valueOf(jsonVal)));
239→            List<Object> list = new ArrayList<>();
240→            for (int i = 0; i < arr.length(); i++) {
241→                list.add(fromJsonValue(arr.get(i), Object.class));
242→            }
243→            return list;
244→        }
245→        if (targetType.isArray()) {
246→            JSONArray arr = (JSONArray) (jsonVal instanceof JSONArray ? jsonVal : new JSONArray(String.valueOf(jsonVal)));
247→            Class<?> componentType = targetType.getComponentType();
248→            Object newArr = java.lang.reflect.Array.newInstance(componentType, arr.length());
249→            for (int i = 0; i < arr.length(); i++) {
250→                Object v = fromJsonValue(arr.get(i), componentType);
251→                java.lang.reflect.Array.set(newArr, i, v);
252→            }
253→            return newArr;
254→        }
255→        JSONObject o = (JSONObject) (jsonVal instanceof JSONObject ? jsonVal : new JSONObject(String.valueOf(jsonVal)));
256→        Object bean = targetType.getDeclaredConstructor().newInstance();
257→        for (PropertyDescriptor pd : Introspector.getBeanInfo(targetType, Object.class).getPropertyDescriptors()) {
258→            Method write = pd.getWriteMethod();
259→            if (write == null) continue;
260→            try { write.setAccessible(true); } catch (Exception ignored) {}
261→            String name = pd.getName();
262→            if (!o.has(name) || o.isNull(name)) continue;
263→            Object raw = o.get(name);
264→
265→            Object converted;
266→            // 优先根据setter泛型做有类型集合转换
267→            try {
268→                Type[] paramTypes = write.getGenericParameterTypes();
269→                if (paramTypes != null && paramTypes.length == 1 && raw instanceof JSONArray) {
270→                    Type p = paramTypes[0];
271→                    if (p instanceof ParameterizedType) {
272→                        ParameterizedType pt = (ParameterizedType) p;
273→                        Type rawType = pt.getRawType();
274→                        if (rawType instanceof Class && Collection.class.isAssignableFrom((Class<?>) rawType)) {
275→                            Type[] typeArgs = pt.getActualTypeArguments();
276→                            if (typeArgs != null && typeArgs.length == 1 && typeArgs[0] instanceof Class) {
277→                                Class<?> elementType = (Class<?>) typeArgs[0];
278→                                converted = convertJsonArrayToList((JSONArray) raw, elementType);
279→                                write.invoke(bean, converted);
280→                                continue;
281→                            }
282→                        }
283→                    }
284→                }
285→            } catch (Exception ignored) {}
286→
287→            // 兜底：根据字段的泛型信息进行集合元素类型转换
288→            try {
289→                if (raw instanceof JSONArray && Collection.class.isAssignableFrom(pd.getPropertyType())) {
290→                    java.lang.reflect.Field f = targetType.getDeclaredField(name);
291→                    Type gt = f.getGenericType();
292→                    if (gt instanceof ParameterizedType) {
293→                        Type[] typeArgs = ((ParameterizedType) gt).getActualTypeArguments();
294→                        if (typeArgs != null && typeArgs.length == 1 && typeArgs[0] instanceof Class) {
295→                            Class<?> elementType = (Class<?>) typeArgs[0];
296→                            converted = convertJsonArrayToList((JSONArray) raw, elementType);
297→                            write.invoke(bean, converted);
298→                            continue;
299→                        }
300→                    }
301→                }
302→            } catch (Exception ignored) {}
303→
304→            converted = fromJsonValue(raw, pd.getPropertyType());
305→            write.invoke(bean, converted);
306→        }
307→
308→        return bean;
309→    }
310→
311→    private static List<Object> convertJsonArrayToList(JSONArray arr, Class<?> elementType) throws Exception {
312→        List<Object> list = new ArrayList<>();
313→        for (int i = 0; i < arr.length(); i++) {
314→            Object item = arr.get(i);
315→            Object converted = fromJsonValue(item, elementType);
316→            list.add(converted);
317→        }
318→        return list;
319→    }
320→}

