    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) {
        if (handleRequest(request, response, getRoutes)) {
            return;
        }

        try {
            renderHomePage(request, response);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws  IOException {
        if (handleRequest(request, response, postRoutes)) {
            return;
        }

        response.sendRedirect(request.getContextPath() + "/plugins/servlet/jiraBot");
    }

    private boolean handleRequest(HttpServletRequest request, HttpServletResponse response,
                                  Map<String, BiConsumer<HttpServletRequest, HttpServletResponse>> routes) {
        String pathInfo = request.getPathInfo();
        if (pathInfo == null) {
            pathInfo = "/";
        }

        BiConsumer<HttpServletRequest, HttpServletResponse> handler = routes.get(pathInfo);
        if (handler != null) {
            handler.accept(request, response);
            return true;
        }

        return false;
    }

