package com.yottastudios.jira.core.support;

import lombok.extern.slf4j.Slf4j;
import org.json.JSONArray;
import org.json.JSONObject;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.beans.Introspector;
import java.beans.PropertyDescriptor;
import java.io.BufferedReader;
import java.io.IOException;
import java.io.PrintWriter;
import java.lang.reflect.Method;
import java.lang.reflect.Modifier;
import java.lang.reflect.ParameterizedType;
import java.lang.reflect.Type;
import java.util.*;
import java.util.function.BiConsumer;

@Slf4j
public final class HttpJsonSupport {

    private HttpJsonSupport() {}

    @FunctionalInterface
    public interface JsonRequestHandler<T> {
        T handle(HttpServletRequest request) throws Exception;
    }

    public static <T> BiConsumer<HttpServletRequest, HttpServletResponse> jsonEndpoint(JsonRequestHandler<T> handler) {
        return (request, response) -> {
            response.setContentType("application/json;charset=UTF-8");
            try {
                T result = handler.handle(request);
                ResponseData<T> wrapped = ResponseData.success(result);
                String json = toJsonString(wrapped);
                PrintWriter out = response.getWriter();
                out.print(json);
                out.flush();
            } catch (Throwable e) {
                try {
                    ResponseData<Void> error = ResponseData.error(e.getMessage());
                    String json = toJsonString(error);
                    PrintWriter out = response.getWriter();
                    out.print(json);
                    out.flush();
                } catch (Exception ignored) {
                }
                log.warn("Error handling JSON endpoint: {}", e.getMessage());
            }
        };
    }

    public static String toJsonString(ResponseData<?> responseData) {
        JSONObject json = new JSONObject();
        json.put("success", responseData.getSuccess());
        json.put("code", responseData.getCode());
        if (responseData.getMessage() != null) {
            json.put("message", responseData.getMessage());
        }
        json.put("data", toJsonValue(responseData.getData()));
        return json.toString();
    }

    public static Object toJsonValue(Object data) {
        if (data == null) {
            return JSONObject.NULL;
        }
        if (data instanceof JSONObject || data instanceof JSONArray) {
            return data;
        }
        if (data instanceof CharSequence || data instanceof Number || data instanceof Boolean) {
            return data;
        }
        if (data instanceof Enum) {
            return ((Enum<?>) data).name();
        }
        if (data instanceof Map) {
            JSONObject obj = new JSONObject();
            Map<?, ?> map = (Map<?, ?>) data;
            for (Map.Entry<?, ?> entry : map.entrySet()) {
                Object key = entry.getKey();
                if (key != null) {
                    obj.put(String.valueOf(key), toJsonValue(entry.getValue()));
                }
            }
            return obj;
        }
        if (data instanceof Collection) {
            JSONArray arr = new JSONArray();
            for (Object item : (Collection<?>) data) {
                arr.put(toJsonValue(item));
            }
            return arr;
        }
        if (data.getClass().isArray()) {
            JSONArray arr = new JSONArray();
            int length = java.lang.reflect.Array.getLength(data);
            for (int i = 0; i < length; i++) {
                Object item = java.lang.reflect.Array.get(data, i);
                arr.put(toJsonValue(item));
            }
            return arr;
        }
        // Try JavaBean via Introspector
        try {
            JSONObject obj = new JSONObject();
            for (PropertyDescriptor pd : Introspector.getBeanInfo(data.getClass(), Object.class).getPropertyDescriptors()) {
                Method readMethod = pd.getReadMethod();
                if (readMethod == null) {
                    continue;
                }
                try { readMethod.setAccessible(true); } catch (Exception ignored) {}
                Object value = readMethod.invoke(data);
                obj.put(pd.getName(), toJsonValue(value));
            }
            if (obj.length() > 0) {
                return obj;
            }
        } catch (Exception ignored) {
        }
        // Fallback: scan public getters
        try {
            JSONObject obj = new JSONObject();
            Method[] methods = data.getClass().getMethods();
            for (Method m : methods) {
                if (m.getParameterCount() != 0) continue;
                if (!Modifier.isPublic(m.getModifiers())) continue;
                String name = m.getName();
                if (name.equals("getClass")) continue;
                if (name.startsWith("get") && name.length() > 3) {
                    String prop = Character.toLowerCase(name.charAt(3)) + name.substring(4);
                    Object value = m.invoke(data);
                    obj.put(prop, toJsonValue(value));
                } else if (name.startsWith("is") && name.length() > 2) {
                    String prop = Character.toLowerCase(name.charAt(2)) + name.substring(3);
                    Object value = m.invoke(data);
                    obj.put(prop, toJsonValue(value));
                }
            }
            if (obj.length() > 0) {
                return obj;
            }
        } catch (Exception ignored) {
        }
        // Last resort: string
        return String.valueOf(data);
    }

    public static <T> T readJsonBody(HttpServletRequest request, Class<T> type) throws Exception {
        String body = readBody(request);
        if (body == null || body.trim().isEmpty()) {
            throw new RuntimeException("请求体不能为空");
        }
        Object json;
        char first = body.trim().charAt(0);
        if (first == '{') {
            json = new JSONObject(body);
        } else if (first == '[') {
            json = new JSONArray(body);
        } else {
            throw new RuntimeException("请求体必须为JSON");
        }
        @SuppressWarnings("unchecked")
        T result = (T) fromJsonValue(json, type);
        return result;
    }

    public static String readBody(HttpServletRequest request) throws IOException {
        StringBuilder sb = new StringBuilder();
        try (BufferedReader reader = request.getReader()) {
            String line;
            while ((line = reader.readLine()) != null) {
                sb.append(line);
            }
        }
        return sb.toString();
    }

    private static Object fromJsonValue(Object jsonVal, Class<?> targetType) throws Exception {
        if (jsonVal == null || jsonVal == JSONObject.NULL) {
            return null;
        }
        if (targetType == Object.class) {
            if (jsonVal instanceof JSONObject) {
                Map<String, Object> map = new HashMap<>();
                JSONObject o = (JSONObject) jsonVal;
                for (java.util.Iterator<String> it = o.keys(); it.hasNext(); ) { String key = it.next();
                    map.put(key, fromJsonValue(o.get(key), Object.class));
                }
                return map;
            }
            if (jsonVal instanceof JSONArray) {
                JSONArray arr = (JSONArray) jsonVal;
                List<Object> list = new ArrayList<>();
                for (int i = 0; i < arr.length(); i++) {
                    list.add(fromJsonValue(arr.get(i), Object.class));
                }
                return list;
            }
            return jsonVal;
        }
        if (CharSequence.class.isAssignableFrom(targetType)) {
            return String.valueOf(jsonVal);
        }
        if (targetType == Integer.class || targetType == int.class) {
            return (jsonVal instanceof Number) ? ((Number) jsonVal).intValue() : Integer.parseInt(String.valueOf(jsonVal));
        }
        if (targetType == Long.class || targetType == long.class) {
            return (jsonVal instanceof Number) ? ((Number) jsonVal).longValue() : Long.parseLong(String.valueOf(jsonVal));
        }
        if (targetType == Double.class || targetType == double.class) {
            return (jsonVal instanceof Number) ? ((Number) jsonVal).doubleValue() : Double.parseDouble(String.valueOf(jsonVal));
        }
        if (targetType == Float.class || targetType == float.class) {
            return (jsonVal instanceof Number) ? ((Number) jsonVal).floatValue() : Float.parseFloat(String.valueOf(jsonVal));
        }
        if (targetType == Boolean.class || targetType == boolean.class) {
            if (jsonVal instanceof Boolean) return jsonVal;
            String s = String.valueOf(jsonVal);
            return "true".equalsIgnoreCase(s) || "1".equals(s);
        }
        if (targetType.isEnum()) {
            @SuppressWarnings("unchecked")
            Class<? extends Enum> enumType = (Class<? extends Enum>) targetType;
            return Enum.valueOf(enumType, String.valueOf(jsonVal));
        }
        if (Map.class.isAssignableFrom(targetType)) {
            Map<String, Object> map = new HashMap<>();
            JSONObject o = (JSONObject) (jsonVal instanceof JSONObject ? jsonVal : new JSONObject(String.valueOf(jsonVal)));
            for (java.util.Iterator<String> it = o.keys(); it.hasNext(); ) { String key = it.next();
                map.put(key, fromJsonValue(o.get(key), Object.class));
            }
            return map;
        }
        if (Collection.class.isAssignableFrom(targetType)) {
            JSONArray arr = (JSONArray) (jsonVal instanceof JSONArray ? jsonVal : new JSONArray(String.valueOf(jsonVal)));
            List<Object> list = new ArrayList<>();
            for (int i = 0; i < arr.length(); i++) {
                list.add(fromJsonValue(arr.get(i), Object.class));
            }
            return list;
        }
        if (targetType.isArray()) {
            JSONArray arr = (JSONArray) (jsonVal instanceof JSONArray ? jsonVal : new JSONArray(String.valueOf(jsonVal)));
            Class<?> componentType = targetType.getComponentType();
            Object newArr = java.lang.reflect.Array.newInstance(componentType, arr.length());
            for (int i = 0; i < arr.length(); i++) {
                Object v = fromJsonValue(arr.get(i), componentType);
                java.lang.reflect.Array.set(newArr, i, v);
            }
            return newArr;
        }
        JSONObject o = (JSONObject) (jsonVal instanceof JSONObject ? jsonVal : new JSONObject(String.valueOf(jsonVal)));
        Object bean = targetType.getDeclaredConstructor().newInstance();
        for (PropertyDescriptor pd : Introspector.getBeanInfo(targetType, Object.class).getPropertyDescriptors()) {
            Method write = pd.getWriteMethod();
            if (write == null) continue;
            try { write.setAccessible(true); } catch (Exception ignored) {}
            String name = pd.getName();
            if (!o.has(name) || o.isNull(name)) continue;
            Object raw = o.get(name);

            Object converted;
            // 优先根据setter泛型做有类型集合转换
            try {
                Type[] paramTypes = write.getGenericParameterTypes();
                if (paramTypes != null && paramTypes.length == 1 && raw instanceof JSONArray) {
                    Type p = paramTypes[0];
                    if (p instanceof ParameterizedType) {
                        ParameterizedType pt = (ParameterizedType) p;
                        Type rawType = pt.getRawType();
                        if (rawType instanceof Class && Collection.class.isAssignableFrom((Class<?>) rawType)) {
                            Type[] typeArgs = pt.getActualTypeArguments();
                            if (typeArgs != null && typeArgs.length == 1 && typeArgs[0] instanceof Class) {
                                Class<?> elementType = (Class<?>) typeArgs[0];
                                converted = convertJsonArrayToList((JSONArray) raw, elementType);
                                write.invoke(bean, converted);
                                continue;
                            }
                        }
                    }
                }
            } catch (Exception ignored) {}

            // 兜底：根据字段的泛型信息进行集合元素类型转换
            try {
                if (raw instanceof JSONArray && Collection.class.isAssignableFrom(pd.getPropertyType())) {
                    java.lang.reflect.Field f = targetType.getDeclaredField(name);
                    Type gt = f.getGenericType();
                    if (gt instanceof ParameterizedType) {
                        Type[] typeArgs = ((ParameterizedType) gt).getActualTypeArguments();
                        if (typeArgs != null && typeArgs.length == 1 && typeArgs[0] instanceof Class) {
                            Class<?> elementType = (Class<?>) typeArgs[0];
                            converted = convertJsonArrayToList((JSONArray) raw, elementType);
                            write.invoke(bean, converted);
                            continue;
                        }
                    }
                }
            } catch (Exception ignored) {}

            converted = fromJsonValue(raw, pd.getPropertyType());
            write.invoke(bean, converted);
        }

        return bean;
    }

    private static List<Object> convertJsonArrayToList(JSONArray arr, Class<?> elementType) throws Exception {
        List<Object> list = new ArrayList<>();
        for (int i = 0; i < arr.length(); i++) {
            Object item = arr.get(i);
            Object converted = fromJsonValue(item, elementType);
            list.add(converted);
        }
        return list;
    }
}

