package com.yottastudios.jira.mapper;

import com.atlassian.activeobjects.external.ActiveObjects;
import com.atlassian.plugin.spring.scanner.annotation.imports.ComponentImport;
import com.yottastudios.jira.ao.TemplateGroup;
import net.java.ao.DBParam;
import net.java.ao.Query;

import javax.inject.Inject;
import javax.inject.Named;
import java.util.List;

@Named
public class TemplateGroupMapper {
    @ComponentImport
    private final ActiveObjects ao;
    private final SequenceGeneratorMapper sequenceMapper;

    @Inject
    public TemplateGroupMapper(ActiveObjects ao, SequenceGeneratorMapper sequenceMapper) {
        this.ao = ao;
        this.sequenceMapper = sequenceMapper;
    }

    public TemplateGroup create(String name) {
        int nextId = sequenceMapper.getNextId();
        return ao.create(TemplateGroup.class,
                new DBParam("ID", nextId),
                new DBParam("NAME", name));
    }

    public TemplateGroup update(int id, String newName) {
        TemplateGroup group = ao.get(TemplateGroup.class, id);
        if (group == null) return null;
        group.setName(newName);
        group.save();
        return group;
    }

    public boolean deleteById(int id) {
        TemplateGroup group = ao.get(TemplateGroup.class, id);
        if (group == null) return false;
        ao.delete(group);
        return true;
    }

    public TemplateGroup[] list() {
        return ao.find(TemplateGroup.class, Query.select().order("SORT_ORDER ASC, ID ASC"));
    }

    public TemplateGroup getById(int id) {
        return ao.get(TemplateGroup.class, id);
    }

    /**
     * 批量更新排序值：按 ids 列表顺序，依次设置 SORT_ORDER = 0, 1, 2, ...
     */
    public void batchUpdateSortOrder(List<Integer> ids) {
        ao.executeInTransaction(() -> {
            for (int i = 0; i < ids.size(); i++) {
                TemplateGroup group = ao.get(TemplateGroup.class, ids.get(i));
                if (group == null) {
                    throw new RuntimeException("分组不存在, id=" + ids.get(i));
                }
                group.setSortOrder(i);
                group.save();
            }
            return null;
        });
    }
}
```

- [ ] **Step 2: 修改 TemplateMapper**

