        this.templateRenderer = templateRenderer;
        this.pluginSettingsFactory = pluginSettingsFactory;
        this.requestFactory = requestFactory;
        this.pageBuilderService = pageBuilderService;
        this.templateGroupMapper = templateGroupMapper;
        this.templateMapper = templateMapper;
        this.issueTemplateMapper = issueTemplateMapper;

        initRoutes();
    }

    @FunctionalInterface
    private interface RequestHandler {
        void handle(HttpServletRequest request, HttpServletResponse response) throws Exception;
    }

    private BiConsumer<HttpServletRequest, HttpServletResponse> withExceptionHandling(RequestHandler handler) {
        return (request, response) -> {
            try {
                handler.handle(request, response);
            } catch (Exception e) {
                log.warn("Error handling request: " + e.getMessage());
                e.printStackTrace();
            }
        };
    }



    private void initRoutes() {
        // GET
        getRoutes.put("/getUserInfo", jsonEndpoint(this::getUserInfo));
        getRoutes.put("/", withExceptionHandling(this::renderHomePage));
        getRoutes.put("/api-docs", withExceptionHandling(this::renderApiDocs));
        getRoutes.put("/blank", withExceptionHandling(this::renderBlankPage));

        // POST
        postRoutes.put("/getUserInfo", jsonEndpoint(this::getUserInfo));
        postRoutes.put("/issue/create", jsonEndpoint(this::createJiraIssue));
        postRoutes.put("/issue/create/batch", jsonEndpoint(this::batchCreateJiraIssues));
        // 仅测试合作任务使用，有问题进行回退
        postRoutes.put("/issue/create/batch2", jsonEndpoint(this::batchCreateJiraIssues2));
        postRoutes.put("/issue/create/v2", jsonEndpoint(this::createJiraIssueV2));
        postRoutes.put("/template-group/create", jsonEndpoint(this::createTemplateGroup));
        postRoutes.put("/template-group/update", jsonEndpoint(this::updateTemplateGroup));
        postRoutes.put("/template-group/delete", jsonEndpoint(this::deleteTemplateGroup));
        postRoutes.put("/template-group/list", jsonEndpoint(this::listTemplateGroups));
        postRoutes.put("/template-group/sort", jsonEndpoint(this::sortTemplateGroups));
        postRoutes.put("/template/create", jsonEndpoint(this::createTemplate));
        postRoutes.put("/template/update", jsonEndpoint(this::updateTemplate));
        postRoutes.put("/template/delete", jsonEndpoint(this::deleteTemplate));
        postRoutes.put("/template/listByGroupId", jsonEndpoint(this::listTemplatesByGroupId));
        postRoutes.put("/template/sort", jsonEndpoint(this::sortTemplates));
        postRoutes.put("/issue-template/create", jsonEndpoint(this::createIssueTemplate));
        postRoutes.put("/issue-template/update", jsonEndpoint(this::updateIssueTemplate));
        postRoutes.put("/issue-template/delete", jsonEndpoint(this::deleteIssueTemplate));
        postRoutes.put("/issue-template/listByTemplate", jsonEndpoint(this::listIssueTemplatesByTemplate));
    }

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) {
        if (handleRequest(request, response, getRoutes)) {
            return;
        }

        try {
            renderHomePage(request, response);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws  IOException {
        if (handleRequest(request, response, postRoutes)) {
            return;
        }

        response.sendRedirect(request.getContextPath() + "/plugins/servlet/jiraBot");
    }

    private boolean handleRequest(HttpServletRequest request, HttpServletResponse response,
                                  Map<String, BiConsumer<HttpServletRequest, HttpServletResponse>> routes) {
        String pathInfo = request.getPathInfo();
        if (pathInfo == null) {
            pathInfo = "/";
        }

        BiConsumer<HttpServletRequest, HttpServletResponse> handler = routes.get(pathInfo);
        if (handler != null) {
            handler.accept(request, response);
            return true;
        }

        return false;
    }

    private void renderHomePage(HttpServletRequest request, HttpServletResponse response) throws Exception {
        templateRenderer.render("home.vm", response.getWriter());
    }

    private void renderApiDocs(HttpServletRequest request, HttpServletResponse response) throws Exception {
        templateRenderer.render("api-docs.vm", response.getWriter());
    }

    private void renderBlankPage(HttpServletRequest request, HttpServletResponse response) throws Exception {
        templateRenderer.render("blank.vm", response.getWriter());
    }

    private SimpleUserInfo getUserInfo(HttpServletRequest request) {
        UserProfile user = userManager.getRemoteUser(request);

        if (user == null) {
            log.warn("无法获取用户信息，userProfile为null");
            throw new RuntimeException("无法获取用户信息");
        }

        JSONObject userInfo = new JSONObject();
        userInfo.put("username", user.getUsername());
        userInfo.put("displayName", user.getFullName());
        userInfo.put("email", user.getEmail());

        return new SimpleUserInfo(user.getUsername(), user.getFullName(), user.getEmail());
    }

    @Data
