    private TemplateGroupVo createTemplateGroup(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");

        TemplateGroupCreateRo ro = readJsonBody(request, TemplateGroupCreateRo.class);
        if (ro == null || ro.getName() == null || ro.getName().trim().isEmpty()) {
            throw new RuntimeException("名称不能为空");
        }
        TemplateGroup created = templateGroupMapper.create(ro.getName().trim());
        return TemplateGroupVo.from(created);
    }

    private TemplateGroupVo updateTemplateGroup(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");

        TemplateGroupUpdateRo ro = readJsonBody(request, TemplateGroupUpdateRo.class);
        if (ro == null || ro.getId() <= 0) throw new RuntimeException("非法ID");
        if (ro.getName() == null || ro.getName().trim().isEmpty()) throw new RuntimeException("名称不能为空");
        TemplateGroup updated = templateGroupMapper.update(ro.getId(), ro.getName().trim());
        if (updated == null) throw new RuntimeException("记录不存在");
        return TemplateGroupVo.from(updated);
    }

    private TemplateGroupDeleteVo deleteTemplateGroup(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");

        TemplateGroupDeleteRo ro = readJsonBody(request, TemplateGroupDeleteRo.class);
        if (ro == null || ro.getId() <= 0) throw new RuntimeException("非法ID");
        boolean success = templateGroupMapper.deleteById(ro.getId());
        return new TemplateGroupDeleteVo(success);
    }

    private List<TemplateGroupVo> listTemplateGroups(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
