        postRoutes.put("/template-group/update", jsonEndpoint(this::updateTemplateGroup));
        postRoutes.put("/template-group/delete", jsonEndpoint(this::deleteTemplateGroup));
        postRoutes.put("/template-group/list", jsonEndpoint(this::listTemplateGroups));
        postRoutes.put("/template-group/sort", jsonEndpoint(this::sortTemplateGroups));
        postRoutes.put("/template/create", jsonEndpoint(this::createTemplate));
        postRoutes.put("/template/update", jsonEndpoint(this::updateTemplate));
        postRoutes.put("/template/delete", jsonEndpoint(this::deleteTemplate));
        postRoutes.put("/template/listByGroupId", jsonEndpoint(this::listTemplatesByGroupId));
        postRoutes.put("/template/sort", jsonEndpoint(this::sortTemplates));
        postRoutes.put("/issue-template/create", jsonEndpoint(this::createIssueTemplate));
        postRoutes.put("/issue-template/update", jsonEndpoint(this::updateIssueTemplate));
        postRoutes.put("/issue-template/delete", jsonEndpoint(this::deleteIssueTemplate));
        postRoutes.put("/issue-template/listByTemplate", jsonEndpoint(this::listIssueTemplatesByTemplate));
    }

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) {
        if (handleRequest(request, response, getRoutes)) {
            return;
        }

        try {
            renderHomePage(request, response);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws  IOException {
        if (handleRequest(request, response, postRoutes)) {
            return;
        }

        response.sendRedirect(request.getContextPath() + "/plugins/servlet/jiraBot");
    }

    private boolean handleRequest(HttpServletRequest request, HttpServletResponse response,
                                  Map<String, BiConsumer<HttpServletRequest, HttpServletResponse>> routes) {
        String pathInfo = request.getPathInfo();
        if (pathInfo == null) {
            pathInfo = "/";
        }

        BiConsumer<HttpServletRequest, HttpServletResponse> handler = routes.get(pathInfo);
        if (handler != null) {
            handler.accept(request, response);
            return true;
        }

        return false;
    }

