    private SimpleUserInfo getUserInfo(HttpServletRequest request) {
        UserProfile user = userManager.getRemoteUser(request);

        if (user == null) {
            log.warn("无法获取用户信息，userProfile为null");
            throw new RuntimeException("无法获取用户信息");
