    private TemplateGroupVo updateTemplateGroup(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");

        TemplateGroupUpdateRo ro = readJsonBody(request, TemplateGroupUpdateRo.class);
        if (ro == null || ro.getId() <= 0) throw new RuntimeException("非法ID");
