    private Map<String, Object> sortTemplateGroups(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");

        TemplateGroupSortRo ro = readJsonBody(request, TemplateGroupSortRo.class);
        if (ro == null || ro.getIds() == null || ro.getIds().isEmpty()) {
