    private CreatedIssueInfo createJiraIssue(HttpServletRequest request) throws Exception {
        // 用户校验与上下文
        UserProfile userProfile = userManager.getRemoteUser(request);
        if (userProfile == null) {
            throw new RuntimeException("未登录");
        }
        ApplicationUser applicationUser = ComponentAccessor.getUserManager().getUserByName(userProfile.getUsername());
        if (applicationUser == null) {
            throw new RuntimeException("无法获取应用用户");
        }
        JiraAuthenticationContext jiraAuthenticationContext = ComponentAccessor.getJiraAuthenticationContext();
        jiraAuthenticationContext.setLoggedInUser(applicationUser);

        CreateJiraIssueRo ro = readJsonBody(request, CreateJiraIssueRo.class);
        Map<String, Object> fields = ro.getFields();
        if (fields == null) {
            throw new RuntimeException("请求体字段不能为空");
        }

        Issue created = createIssueWithParameters(applicationUser, fields);

        // 创建链接
        if (!isBlank(ro.getTargetLinkIssueKey()) && !isBlank(ro.getLinkTypeName())) {
            createIssueLink(created.getKey(), ro.getTargetLinkIssueKey(), ro.getLinkTypeName(), applicationUser);
        }

        return new CreatedIssueInfo(created.getKey(), created.getId());
    }

    private CreatedIssueInfo createJiraIssueV2(HttpServletRequest request) throws Exception {
        UserProfile userProfile = userManager.getRemoteUser(request);
        if (userProfile == null) throw new RuntimeException("未登录");
        ApplicationUser applicationUser = ComponentAccessor.getUserManager().getUserByName(userProfile.getUsername());
        if (applicationUser == null) throw new RuntimeException("无法获取应用用户");
        JiraAuthenticationContext jiraAuthenticationContext = ComponentAccessor.getJiraAuthenticationContext();
        jiraAuthenticationContext.setLoggedInUser(applicationUser);

        String body = readBody(request);
        if (body == null || body.trim().isEmpty()) throw new RuntimeException("请求体不能为空");
        JSONObject obj = new JSONObject(body);
        CreateJiraIssueV2Ro ro = CreateJiraIssueV2Ro.parseCreateJiraIssueV2(obj);
        if (ro.getFields() == null) throw new RuntimeException("请求体字段不能为空");

        Issue created = createIssueWithParameters(applicationUser, ro.getFields());

        if (ro.getLinks() != null) {
            for (com.yottastudios.jira.ro.LinkCreateRo link : ro.getLinks()) {
                if (link == null) continue;
                if (isBlank(link.getLinkTypeName()) || isBlank(link.getTargetIssueKey())) continue;
                createIssueLink(created.getKey(), link.getTargetIssueKey(), link.getLinkTypeName(), applicationUser);
            }
        }

        return new CreatedIssueInfo(created.getKey(), created.getId());
    }

    private List<CreatedIssueInfo> batchCreateJiraIssues(HttpServletRequest request) throws Exception {
        UserProfile userProfile = userManager.getRemoteUser(request);
        if (userProfile == null) throw new RuntimeException("未登录");
        ApplicationUser applicationUser = ComponentAccessor.getUserManager().getUserByName(userProfile.getUsername());
        if (applicationUser == null) throw new RuntimeException("无法获取应用用户");
        JiraAuthenticationContext jiraAuthenticationContext = ComponentAccessor.getJiraAuthenticationContext();
        jiraAuthenticationContext.setLoggedInUser(applicationUser);

        String body = readBody(request);
        if (body == null || body.trim().isEmpty()) throw new RuntimeException("请求体不能为空");
        JSONObject root = new JSONObject(body);
        if (!root.has("issues")) throw new RuntimeException("issues不能为空");
        JSONArray arr = root.getJSONArray("issues");
        if (arr.length() == 0) throw new RuntimeException("issues不能为空");

        List<CreateJiraIssueV2Ro> issueRos = new ArrayList<>();
        for (int i = 0; i < arr.length(); i++) {
            Object item = arr.get(i);
            if (!(item instanceof JSONObject)) throw new RuntimeException("issues项必须为对象");
            issueRos.add(CreateJiraIssueV2Ro.parseCreateJiraIssueV2((JSONObject) item));
        }

        for (CreateJiraIssueV2Ro item : issueRos) {
            if (item.getIssueTemplateId() == null) throw new RuntimeException("每个issue必须包含issueTemplateId");
            if (item.getFields() == null) throw new RuntimeException("请求体字段不能为空");
        }

        Map<Long, CreateJiraIssueV2Ro> templateIdToItem = new LinkedHashMap<>();
        for (CreateJiraIssueV2Ro item : issueRos) {
            Long id = item.getIssueTemplateId();
            if (templateIdToItem.containsKey(id)) throw new RuntimeException("issueTemplateId重复: " + id);
            templateIdToItem.put(id, item);
        }

        Map<Long, List<Long>> edges = new HashMap<>();
        Map<Long, Integer> indegree = new HashMap<>();
        for (Long id : templateIdToItem.keySet()) indegree.put(id, 0);
        for (CreateJiraIssueV2Ro item : issueRos) {
            Long parent = item.getParentIssueTemplateId();
            if (parent != null) {
                if (!templateIdToItem.containsKey(parent)) throw new RuntimeException("未找到依赖的issueTemplateId: " + parent);
                edges.computeIfAbsent(parent, k -> new ArrayList<>()).add(item.getIssueTemplateId());
                indegree.put(item.getIssueTemplateId(), indegree.get(item.getIssueTemplateId()) + 1);
            }
            List<Long> ups = item.getUpstreamIssueTemplateIds();
            if (ups != null) {
                for (Long up : ups) {
                    if (up == null) continue;
                    if (!templateIdToItem.containsKey(up)) throw new RuntimeException("未找到依赖的issueTemplateId: " + up);
                    edges.computeIfAbsent(up, k -> new ArrayList<>()).add(item.getIssueTemplateId());
                    indegree.put(item.getIssueTemplateId(), indegree.get(item.getIssueTemplateId()) + 1);
                }
            }
        }

        Set<Long> nodesWithChildren = new HashSet<>(edges.keySet());
        Set<Long> nodesReferencedAsChild = new HashSet<>();
        for (List<Long> children : edges.values()) nodesReferencedAsChild.addAll(children);
        Set<Long> inGraph = new HashSet<>();
        inGraph.addAll(nodesWithChildren);
        inGraph.addAll(nodesReferencedAsChild);

        Deque<Long> queue = new ArrayDeque<>();
        for (Long id : inGraph) if (indegree.get(id) == 0) queue.addLast(id);
        List<Long> topoOrder = new ArrayList<>();
        while (!queue.isEmpty()) {
            Long u = queue.removeFirst();
            topoOrder.add(u);
            List<Long> children = edges.get(u);
            if (children == null || children.isEmpty()) continue;
            for (Long v : children) {
                int d = indegree.get(v) - 1;
                indegree.put(v, d);
                if (d == 0) queue.addLast(v);
            }
        }
        if (topoOrder.size() != inGraph.size()) throw new RuntimeException("存在循环依赖，请检查上游/父任务设置");

        List<Long> standalone = new ArrayList<>();
        for (CreateJiraIssueV2Ro item : issueRos) {
            Long id = item.getIssueTemplateId();
            boolean noParent = item.getParentIssueTemplateId() == null;
            List<Long> ups = item.getUpstreamIssueTemplateIds();
            boolean noUpstreams = ups == null || ups.isEmpty();
            if (noParent && noUpstreams && !inGraph.contains(id)) standalone.add(id);
        }
        List<Long> orderedIds = new ArrayList<>();
        orderedIds.addAll(topoOrder);
        orderedIds.addAll(standalone);

        String dependencyTreeLog = renderDependencyForest(edges, inGraph, standalone);
        log.error("批量创建依赖关系树:\n{}", dependencyTreeLog);

        for (Long id : orderedIds) {
            CreateJiraIssueV2Ro item = templateIdToItem.get(id);
            validateIssueFields(applicationUser, item.getFields());
        }

        Map<Long, String> templateIdToIssueKey = new HashMap<>();
        List<CreatedIssueInfo> results = new ArrayList<>();
        for (Long id : orderedIds) {
            CreateJiraIssueV2Ro item = templateIdToItem.get(id);
            Map<String, Object> fields = item.getFields();

            Issue created = createIssueWithParameters(applicationUser, fields);

            Long parent = item.getParentIssueTemplateId();
            if (parent != null) {
                String parentKey = templateIdToIssueKey.get(parent);
                if (parentKey == null) throw new RuntimeException("内部错误：未找到依赖创建结果: " + parent);
                createIssueLink(created.getKey(), parentKey, LINK_TYPE_PARENT, applicationUser);
            }

            List<Long> ups = item.getUpstreamIssueTemplateIds();
            if (ups != null) {
                for (Long up : ups) {
                    if (up == null) continue;
                    String upKey = templateIdToIssueKey.get(up);
                    if (upKey == null) throw new RuntimeException("内部错误：未找到依赖创建结果: " + up);
                    createIssueLink(created.getKey(), upKey, LINK_TYPE_UPSTREAM, applicationUser);
                }
            }

            if (item.getLinks() != null) {
                Set<String> autoPairs = new HashSet<>();
                if (parent != null) autoPairs.add(LINK_TYPE_PARENT + "@" + templateIdToIssueKey.get(parent));
                if (ups != null) {
                    for (Long up : ups) {
                        if (up == null) continue;
                        String upKey = templateIdToIssueKey.get(up);
                        if (upKey != null) autoPairs.add(LINK_TYPE_UPSTREAM + "@" + upKey);
                    }
                }
                for (LinkCreateRo link : item.getLinks()) {
                    if (link == null) continue;
                    String type = link.getLinkTypeName();
                    String tgt = link.getTargetIssueKey();
                    if (isBlank(type) || isBlank(tgt)) continue;
                    String pair = type + "@" + tgt;
                    if (autoPairs.contains(pair)) continue;
                    createIssueLink(created.getKey(), tgt, type, applicationUser);
                }
            }

            templateIdToIssueKey.put(id, created.getKey());
            results.add(new CreatedIssueInfo(created.getKey(), created.getId()));
        }
        return results;
    }




