    private List<JSONObject> transJsonList(Object item) {
        List<JSONObject> resultList = new ArrayList<>();

        log.warn("=== 开始处理单个issue对象 ===");
        log.warn("输入的issue对象: {}", item);

        try {
            JSONObject issue = (JSONObject) item;
            JSONObject fields = issue.getJSONObject("fields");

            if (fields == null || !fields.keySet().contains("customfield_10403")) {
                log.warn("issue的fields字段为空，直接返回原对象");
                resultList.add(issue);
                return resultList;
            }

            log.warn("fields字段内容: {}", fields);

            // 获取项目键列表（从customfield_10403）
            String customField10403 = fields.getString("customfield_10403");
            log.warn("customfield_10403字段值: {}", customField10403);

            if (customField10403 == null || customField10403.trim().isEmpty()) {
                log.warn("customfield_10403字段为空，直接返回原对象");
                resultList.add(issue);
                return resultList;
            }

            // 按逗号分割项目键
            String[] projectKeys = customField10403.split(",");
            log.warn("分割后的项目键数组: {}", Arrays.toString(projectKeys));

            // 需要特殊处理的字段名
            String[] targetFields = {"customfield_11008", "customfield_11026",
                    "customfield_11006", "customfield_11004"};

            // 为每个项目键创建一个新的JSON对象
            for (String projectKey : projectKeys) {
                projectKey = projectKey.trim();
                log.warn("处理项目键: '{}'", projectKey);

                // 复制整个issue对象，保留所有原有字段
                JSONObject newJson = deepCopyJson(issue);
                JSONObject newFields = newJson.getJSONObject("fields");

                // 设置customfield_10403为当前项目键
                newFields.put("customfield_10403", projectKey);

                // 处理目标字段
                for (String fieldName : targetFields) {
                    if (!fields.has(fieldName)){
                        continue;
                    }
                    Object fieldValue = fields.get(fieldName);
                    String processedValue = processFieldForProjectKey(fieldValue, projectKey);
                    newFields.put(fieldName, processedValue);
                    log.warn("字段'{}'处理完成: {}", fieldName, processedValue);
                }
                // 随机生成模板id
                Random random = new Random();
                newJson.put("issueTemplateId", Math.abs(random.nextLong()));

                log.warn("生成的新对象: {}", newJson);
                resultList.add(newJson);
            }

            log.warn("处理完成，从1个对象生成了{}个对象", resultList.size());

        } catch (Exception e) {
            log.error("处理issue对象时发生错误: {}", e.getMessage(), e);
            log.error("出错的输入数据: {}", item);
        }

        return resultList;
    }

    /**
     * 根据项目键处理字段值
     * 从数组中找到以项目键开头的值，去掉前缀返回
     */
    private String processFieldForProjectKey(Object fieldValue, String projectKey) {
        log.warn("      ~~~> 开始处理字段值匹配，项目键: '{}'", projectKey);
        log.warn("      ~~~> 输入字段值: {} (类型: {})", fieldValue, fieldValue != null ? fieldValue.getClass().getSimpleName() : "null");

        if (fieldValue == null) {
            log.warn("      ~~~> 字段值为null，返回空字符串");
            return "";
        }

        try {
            List<String> valueList = new ArrayList<>();

            // 解析字段值为字符串数组
            if (fieldValue instanceof JSONArray) {
                log.warn("      ~~~> 字段值是JSONArray类型");
                JSONArray array = (JSONArray) fieldValue;
                for (int i = 0; i < array.length(); i++) {
                    Object item = array.get(i);
                    if (item != null) {
                        valueList.add(item.toString());
                        log.warn("      ~~~> 从JSONArray中提取值[{}]: '{}'", i, item.toString());
                    }
                }
            } else if (fieldValue instanceof List) {
                log.warn("      ~~~> 字段值是List类型");
                List<?> list = (List<?>) fieldValue;
                for (int i = 0; i < list.size(); i++) {
                    Object item = list.get(i);
                    if (item != null) {
                        valueList.add(item.toString());
                        log.warn("      ~~~> 从List中提取值[{}]: '{}'", i, item.toString());
                    }
                }
            } else if (fieldValue instanceof Object[]) {
                log.warn("      ~~~> 字段值是Object[]类型");
                Object[] array = (Object[]) fieldValue;
                for (int i = 0; i < array.length; i++) {
                    Object item = array[i];
                    if (item != null) {
                        valueList.add(item.toString());
                        log.warn("      ~~~> 从Object[]中提取值[{}]: '{}'", i, item.toString());
                    }
                }
            } else {
                log.warn("      ~~~> 字段值是单个值类型");
                valueList.add(fieldValue.toString());
                log.warn("      ~~~> 单个值: '{}'", fieldValue.toString());
            }

            log.warn("      ~~~> 解析完成，值列表: {}", valueList);

            // 在数组中查找以当前项目键开头的值
            String prefix = projectKey + "-";
            log.warn("      ~~~> 查找前缀: '{}'", prefix);

            for (int i = 0; i < valueList.size(); i++) {
                String value = valueList.get(i);
                log.warn("      ~~~> 检查值[{}]: '{}' 是否以前缀'{}'开头", i, value, prefix);

                if (value != null && value.startsWith(prefix)) {
                    String result = value.substring(prefix.length());
                    log.warn("      ~~~> ✓ 找到匹配值！原值: '{}' -> 去前缀后: '{}'", value, result);
                    return result;
                }
            }

            log.warn("      ~~~> ✗ 没找到以'{}'开头的匹配值，返回空字符串", prefix);
            return "";

        } catch (Exception e) {
            log.error("      ~~~> 处理字段值时发生错误，字段值: {}, 项目键: {}, 错误: {}",
                    fieldValue, projectKey, e.getMessage(), e);
            return "";
        }
    }

    /**
     * JSON深拷贝方法，保留所有字段
     */
    private JSONObject deepCopyJson(JSONObject original) {
        log.debug("开始深拷贝JSON对象，原对象键数量: {}", original.keySet().size());

        JSONObject copy = new JSONObject();

        // 遍历原对象的所有键值对
        for (String key : original.keySet()) {
            Object value = original.get(key);
            log.debug("拷贝字段 '{}': {} (类型: {})", key, value, value != null ? value.getClass().getSimpleName() : "null");

            if (value instanceof JSONObject) {
                log.debug("字段'{}'是JSONObject，进行递归拷贝", key);
                copy.put(key, deepCopyJson((JSONObject) value));
            } else if (value instanceof JSONArray) {
                log.debug("字段'{}'是JSONArray，进行数组拷贝", key);
                JSONArray originalArray = (JSONArray) value;
                JSONArray copyArray = new JSONArray();
                for (int i = 0; i < originalArray.length(); i++) {
                    Object arrayItem = originalArray.get(i);
                    if (arrayItem instanceof JSONObject) {
                        copyArray.put(deepCopyJson((JSONObject) arrayItem));
                    } else {
                        copyArray.put(arrayItem);
                    }
                }
                copy.put(key, copyArray);
            } else {
                log.debug("字段'{}'是基本类型，直接拷贝", key);
                copy.put(key, value);
            }
        }

        log.debug("深拷贝完成，新对象键数量: {}", copy.keySet().size());
        return copy;
    }





    private List<Issue> findCooperationLinkedIssue(Issue issue) {
        IssueLinkManager issueLinkManager = ComponentAccessor.getIssueLinkManager();
        List<Issue> issueList = new ArrayList<>();

        // 获取入站链接
        List<IssueLink> inwardLinks = issueLinkManager.getInwardLinks(issue.getId());
        if (inwardLinks != null) {
            inwardLinks.forEach(issueLink -> {
                if (issueLink.getIssueLinkType() != null &&
                        "合作".equals(issueLink.getIssueLinkType().getName())) {
                    Issue sourceIssue = issueLink.getSourceObject();
                    if (sourceIssue != null) {
                        issueList.add(sourceIssue);
                    }
                }
            });
        }

        // 获取出站链接
        List<IssueLink> outwardLinks = issueLinkManager.getOutwardLinks(issue.getId());
        if (outwardLinks != null) {
            outwardLinks.forEach(issueLink -> {
                if (issueLink.getIssueLinkType() != null &&
                        "合作".equals(issueLink.getIssueLinkType().getName())) {
                    Issue destinationIssue = issueLink.getDestinationObject();
                    if (destinationIssue != null) {
                        issueList.add(destinationIssue);
                    }
                }
            });
        }

        return issueList;
    }


    public Map<String, Map<String, Object>> transformDataSimple(Map<String, Map<String, Object>> originalData) {
        Map<String, Map<String, Object>> result = new HashMap<>();

        for (Map.Entry<String, Map<String, Object>> entry : originalData.entrySet()) {
            String issueKey = entry.getKey(); // "PX-556"
            Map<String, Object> fields = entry.getValue();

            Map<String, Object> newStructure = new HashMap<>();

            // 遍历所有字段
            for (Map.Entry<String, Object> fieldEntry : fields.entrySet()) {
                String fieldName = fieldEntry.getKey(); // "customfield_11004"
                Object fieldValue = fieldEntry.getValue(); // 这个值是一个string数组[PXTL-nuoyan,PX-feibai]

                // 解析字段值，提取groupname和username
                List<String> parsedData = parseFieldValue(fieldValue);
                parsedData.forEach(data -> {
                    String[] splitData = data.split("-");
                    if (splitData.length != 2){
                        return;
                    }
                    String groupname = splitData[0];
                    String username = splitData[1];
                    // 只有groupname和username都不为空时才处理
                    if (groupname != null && !groupname.trim().isEmpty() &&
                            username != null && !username.trim().isEmpty()) {

                        if (newStructure.containsKey(groupname)){
                            Object object = newStructure.get(groupname);
                            if (object instanceof Map) {
                                @SuppressWarnings("unchecked")
                                Map<String, String> valueMap = (Map<String, String>) object;
                                valueMap.put(fieldName, username);
                            }
                        } else {
                            Map<String, String> valueMap = new HashMap<>();
                            valueMap.put(fieldName, username);
                            newStructure.put(groupname, valueMap);
                        }
                    }
                });
            }
            result.put(issueKey, newStructure);
        }

        return result;
    }


    public List<String> parseFieldValue(Object fieldValue) {
        List<String> result = new ArrayList<>();

        if (fieldValue == null) {
            return result;
        }

        // 数组类型
        if (fieldValue instanceof Object[]) {
            Object[] array = (Object[]) fieldValue;
            for (Object item : array) {
                if (item != null) {
                    result.add(item.toString());
                }
            }
        }
        // 集合类型
        else if (fieldValue instanceof Collection) {
            Collection<?> collection = (Collection<?>) fieldValue;
            for (Object item : collection) {
                if (item != null) {
                    result.add(item.toString());
                }
            }
        }
        // 字符串类型
        else {
            result.add(fieldValue.toString());
        }

        return result;
    }


    private Map<String, Object> filterSpecialFields(Map<String, Object> fields) {
        Map<String, Object> specialFields = new HashMap<>();
        // customfield_11008 承接组pm  customfield_11026 承接组qa customfield_11006 承接组程序 customfield_11004 承接组策划
        List<String> specialKeys = Arrays.asList("customfield_11008","customfield_11026","customfield_11006","customfield_11004");

        if (fields != null) {
            fields.forEach((key, value) -> {
                if (key != null && specialKeys.contains(key) && value != null) {
                    specialFields.put(key, value);
                }
            });
            specialFields.forEach(fields::remove);
        }

        return specialFields;
    }

    private String renderDependencyForest(Map<Long, List<Long>> edges, Set<Long> inGraph, List<Long> standalone) {
        StringBuilder sb = new StringBuilder();
        Set<Long> referenced = new HashSet<>();
        for (List<Long> children : edges.values()) referenced.addAll(children);
        List<Long> roots = new ArrayList<>();
        for (Long id : inGraph) if (!referenced.contains(id)) roots.add(id);

        if (!roots.isEmpty()) sb.append("依赖树:\n");
        for (Long root : roots) appendDependencyTree(root, edges, "", sb);

        if (!standalone.isEmpty()) {
            if (sb.length() > 0) sb.append('\n');
            sb.append("独立节点(无上下游): ");
            for (int i = 0; i < standalone.size(); i++) {
                if (i > 0) sb.append(", ");
                sb.append(standalone.get(i));
            }
        }
        return sb.toString();
    }

    private void appendDependencyTree(Long nodeId, Map<Long, List<Long>> edges, String indent, StringBuilder sb) {
        sb.append(indent).append("- ").append(nodeId).append('\n');
        List<Long> children = edges.get(nodeId);
        if (children == null || children.isEmpty()) return;
        String childIndent = indent + "  ";
        for (Long child : children) appendDependencyTree(child, edges, childIndent, sb);
    }

