/**
 * 模板排序功能 - 接口测试脚本
 *
 * 用法: node 05-test-api.js
 * 要求: Node.js 18+（原生 fetch）
 * 说明: Jira 插件接口，需要 Jira 登录态（cookie）
 *       先在浏览器登录 Jira，复制 cookie 到下方 CONFIG.cookie
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'https://xjira-private.yottastudios.com',
  basePath: '/plugins/servlet/jiraBot',
  // 从浏览器 DevTools > Application > Cookies 复制完整 cookie
  cookie: process.env.JIRA_COOKIE || 'JSESSIONID=xxx; atlassian.xsrf.token=xxx',
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  \u2705 ${name}`);
    passed++;
  } else {
    console.log(`  \u274C ${name}`);
    if (detail !== undefined)
      console.log(`     \u5B9E\u9645\u503C:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========
async function POST(path, body) {
  const url = `${CONFIG.host}${CONFIG.basePath}${path}`;
  const res = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Cookie': CONFIG.cookie,
    },
    body: JSON.stringify(body || {}),
  });
  return res.json();
}

// ========== 测试数据管理 ==========
let testGroupId = null;
let testTemplateIds = [];

async function setupTestData() {
  console.log('\n\uD83D\uDCE6 \u521B\u5EFA\u6D4B\u8BD5\u6570\u636E...');

  // 创建测试分组
  const g = await POST('/template-group/create', { name: 'TEST_SORT_GROUP_' + Date.now() });
  assert('\u521B\u5EFA\u6D4B\u8BD5\u5206\u7EC4', g.success === true, g);
  testGroupId = g.data?.id;
  if (!testGroupId) {
    console.log('  \u26A0\uFE0F \u521B\u5EFA\u5206\u7EC4\u5931\u8D25\uFF0C\u8DF3\u8FC7\u5199\u64CD\u4F5C\u6D4B\u8BD5');
    return false;
  }

  // 创建 3 个测试模板
  for (let i = 1; i <= 3; i++) {
    const t = await POST('/template/create', {
      projectKey: 'PXTL',
      name: `TEST_SORT_TMPL_${i}_${Date.now()}`,
      groupId: testGroupId,
    });
    assert(`\u521B\u5EFA\u6D4B\u8BD5\u6A21\u677F${i}`, t.success === true, t);
    if (t.data?.id) testTemplateIds.push(t.data.id);
  }

  console.log(`  \u2139\uFE0F groupId=${testGroupId}, templateIds=${JSON.stringify(testTemplateIds)}`);
  return testTemplateIds.length === 3;
}

async function cleanupTestData() {
  console.log('\n\uD83E\uDDF9 \u6E05\u7406\u6D4B\u8BD5\u6570\u636E...');
  for (const id of testTemplateIds) {
    await POST('/template/delete', { id });
  }
  if (testGroupId) {
    await POST('/template-group/delete', { id: testGroupId });
  }
  console.log('  \u2139\uFE0F \u6E05\u7406\u5B8C\u6210');
}

// ========== 测试用例 ==========

// §1. 分组列表排序
async function test_§1_groupList() {
  console.log('\n\uD83D\uDCCB \u00A71. \u5206\u7EC4\u5217\u8868\u67E5\u8BE2\uFF08\u5E26\u6392\u5E8F\uFF09');

  const res = await POST('/template-group/list', {});
  assert('\u00A71 \u63A5\u53E3\u8FD4\u56DE success', res.success === true, res);
  assert('\u00A71 data \u662F\u6570\u7EC4', Array.isArray(res.data), res.data);

  if (Array.isArray(res.data) && res.data.length > 0) {
    const first = res.data[0];
    assert('\u00A71 \u5206\u7EC4\u542B id (number)', typeof first.id === 'number', first.id);
    assert('\u00A71 \u5206\u7EC4\u542B name (string)', typeof first.name === 'string', first.name);
    assert('\u00A71 \u5206\u7EC4\u542B sortOrder (number)', typeof first.sortOrder === 'number', first.sortOrder);

    // 验证排序：sortOrder 递增
    let sorted = true;
    for (let i = 1; i < res.data.length; i++) {
      if (res.data[i].sortOrder < res.data[i - 1].sortOrder) {
        sorted = false;
        break;
      }
    }
    assert('\u00A71 \u5206\u7EC4\u5217\u8868\u6309 sortOrder \u5347\u5E8F', sorted);
  }
}

// §2. 模板列表排序
async function test_§2_templateList() {
  console.log('\n\uD83D\uDCCB \u00A72. \u6A21\u677F\u5217\u8868\u67E5\u8BE2\uFF08\u5E26\u6392\u5E8F\uFF09');

  if (!testGroupId) { console.log('  \u26A0\uFE0F \u65E0\u6D4B\u8BD5\u5206\u7EC4\uFF0C\u8DF3\u8FC7'); return; }

  const res = await POST('/template/listByGroupId', { groupId: testGroupId });
  assert('\u00A72 \u63A5\u53E3\u8FD4\u56DE success', res.success === true, res);
  assert('\u00A72 data \u662F\u6570\u7EC4', Array.isArray(res.data), res.data);

  if (Array.isArray(res.data) && res.data.length > 0) {
    const first = res.data[0];
    assert('\u00A72 \u6A21\u677F\u542B id (number)', typeof first.id === 'number', first.id);
    assert('\u00A72 \u6A21\u677F\u542B name (string)', typeof first.name === 'string', first.name);
    assert('\u00A72 \u6A21\u677F\u542B groupId (number)', typeof first.groupId === 'number', first.groupId);
    assert('\u00A72 \u6A21\u677F\u542B sortOrder (number)', typeof first.sortOrder === 'number', first.sortOrder);
    assert('\u00A72 groupId \u4E0E\u8BF7\u6C42\u4E00\u81F4', first.groupId === testGroupId, first.groupId);
  }
}

// §3. 分组排序接口 - 正常流程
async function test_§3_sortGroups_normal() {
  console.log('\n\u2B50 \u00A73. \u5206\u7EC4\u6392\u5E8F - \u6B63\u5E38\u6D41\u7A0B');

  // 先获取当前所有分组
  const listRes = await POST('/template-group/list', {});
  if (!Array.isArray(listRes.data) || listRes.data.length < 2) {
    console.log('  \u26A0\uFE0F \u5206\u7EC4\u4E0D\u8DB3 2 \u4E2A\uFF0C\u8DF3\u8FC7\u6392\u5E8F\u6D4B\u8BD5');
    return;
  }

  const ids = listRes.data.map(g => g.id);
  const reversedIds = [...ids].reverse();

  // 排序：反转顺序
  const sortRes = await POST('/template-group/sort', { ids: reversedIds });
  assert('\u00A73 \u5206\u7EC4\u6392\u5E8F\u8FD4\u56DE success', sortRes.success === true, sortRes);

  // 验证排序生效
  const afterList = await POST('/template-group/list', {});
  assert('\u00A73 \u6392\u5E8F\u540E\u5217\u8868 success', afterList.success === true);
  const afterIds = afterList.data.map(g => g.id);
  assert('\u00A73 \u6392\u5E8F\u540E\u987A\u5E8F\u4E0E\u63D0\u4EA4\u4E00\u81F4', JSON.stringify(afterIds) === JSON.stringify(reversedIds),
    { expected: reversedIds, actual: afterIds });

  // 验证 sortOrder 值递增
  let sortOrderCorrect = true;
  for (let i = 0; i < afterList.data.length; i++) {
    if (afterList.data[i].sortOrder !== i) {
      sortOrderCorrect = false;
      break;
    }
  }
  assert('\u00A73 sortOrder \u503C\u4E3A 0,1,2,...', sortOrderCorrect);

  // 还原顺序
