// §9. 并发请求
async function test_§9_concurrency() {
  console.log('\n\uD83D\uDD00 \u00A79. \u5E76\u53D1\u8BF7\u6C42');

  // 5 个并发 list 请求
  const promises = Array.from({ length: 5 }, () =>
    POST('/template-group/list', {})
  );
  const results = await Promise.all(promises);
  const allOk = results.every(r => r.success === true);
  assert('\u00A79 5\u4E2A\u5E76\u53D1 list \u90FD\u6210\u529F', allOk);

  // 验证返回数据一致
  if (allOk) {
    const totals = results.map(r => r.data.length);
    const allSame = totals.every(t => t === totals[0]);
    assert('\u00A79 \u5E76\u53D1\u8FD4\u56DE\u6570\u636E\u91CF\u4E00\u81F4', allSame, totals);
  }
}

// §10. 响应结构一致性
async function test_§10_responseStructure() {
