/**
 * 模板排序功能 - 接口测试脚本
 *
 * 用法: node 05-test-api.js
 * 要求: Node.js 18+（原生 fetch）
 * 说明: Jira 插件接口，需要 Jira 登录态（cookie）
 *       先在浏览器登录 Jira，复制 cookie 到下方 CONFIG.cookie
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'https://xjira-private.yottastudios.com',
  basePath: '/plugins/servlet/jiraBot',
  // 从浏览器 DevTools > Application > Cookies 复制完整 cookie
  cookie: process.env.JIRA_COOKIE || 'JSESSIONID=xxx; atlassian.xsrf.token=xxx',
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  \u2705 ${name}`);
    passed++;
  } else {
    console.log(`  \u274C ${name}`);
    if (detail !== undefined)
      console.log(`     \u5B9E\u9645\u503C:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========
async function POST(path, body) {
  const url = `${CONFIG.host}${CONFIG.basePath}${path}`;
  const res = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Cookie': CONFIG.cookie,
    },
    body: JSON.stringify(body || {}),
  });
  return res.json();
}

// ========== 测试数据管理 ==========
let testGroupId = null;
let testTemplateIds = [];

async function setupTestData() {
  console.log('\n\uD83D\uDCE6 \u521B\u5EFA\u6D4B\u8BD5\u6570\u636E...');

  // 创建测试分组
  const g = await POST('/template-group/create', { name: 'TEST_SORT_GROUP_' + Date.now() });
  assert('\u521B\u5EFA\u6D4B\u8BD5\u5206\u7EC4', g.success === true, g);
  testGroupId = g.data?.id;
  if (!testGroupId) {
    console.log('  \u26A0\uFE0F \u521B\u5EFA\u5206\u7EC4\u5931\u8D25\uFF0C\u8DF3\u8FC7\u5199\u64CD\u4F5C\u6D4B\u8BD5');
    return false;
  }

  // 创建 3 个测试模板
  for (let i = 1; i <= 3; i++) {
    const t = await POST('/template/create', {
      projectKey: 'PXTL',
      name: `TEST_SORT_TMPL_${i}_${Date.now()}`,
      groupId: testGroupId,
    });
    assert(`\u521B\u5EFA\u6D4B\u8BD5\u6A21\u677F${i}`, t.success === true, t);
    if (t.data?.id) testTemplateIds.push(t.data.id);
  }

  console.log(`  \u2139\uFE0F groupId=${testGroupId}, templateIds=${JSON.stringify(testTemplateIds)}`);
  return testTemplateIds.length === 3;
}

async function cleanupTestData() {
  console.log('\n\uD83E\uDDF9 \u6E05\u7406\u6D4B\u8BD5\u6570\u636E...');
  for (const id of testTemplateIds) {
    await POST('/template/delete', { id });
  }
  if (testGroupId) {
    await POST('/template-group/delete', { id: testGroupId });
  }
  console.log('  \u2139\uFE0F \u6E05\u7406\u5B8C\u6210');
}

// ========== 测试用例 ==========

// §1. 分组列表排序
async function test_§1_groupList() {
  console.log('\n\uD83D\uDCCB \u00A71. \u5206\u7EC4\u5217\u8868\u67E5\u8BE2\uFF08\u5E26\u6392\u5E8F\uFF09');

  const res = await POST('/template-group/list', {});
  assert('\u00A71 \u63A5\u53E3\u8FD4\u56DE success', res.success === true, res);
  assert('\u00A71 data \u662F\u6570\u7EC4', Array.isArray(res.data), res.data);

  if (Array.isArray(res.data) && res.data.length > 0) {
    const first = res.data[0];
    assert('\u00A71 \u5206\u7EC4\u542B id (number)', typeof first.id === 'number', first.id);
    assert('\u00A71 \u5206\u7EC4\u542B name (string)', typeof first.name === 'string', first.name);
    assert('\u00A71 \u5206\u7EC4\u542B sortOrder (number)', typeof first.sortOrder === 'number', first.sortOrder);

    // 验证排序：sortOrder 递增
    let sorted = true;
    for (let i = 1; i < res.data.length; i++) {
      if (res.data[i].sortOrder < res.data[i - 1].sortOrder) {
        sorted = false;
        break;
      }
    }
    assert('\u00A71 \u5206\u7EC4\u5217\u8868\u6309 sortOrder \u5347\u5E8F', sorted);
  }
}

// §2. 模板列表排序
async function test_§2_templateList() {
  console.log('\n\uD83D\uDCCB \u00A72. \u6A21\u677F\u5217\u8868\u67E5\u8BE2\uFF08\u5E26\u6392\u5E8F\uFF09');

  if (!testGroupId) { console.log('  \u26A0\uFE0F \u65E0\u6D4B\u8BD5\u5206\u7EC4\uFF0C\u8DF3\u8FC7'); return; }

  const res = await POST('/template/listByGroupId', { groupId: testGroupId });
  assert('\u00A72 \u63A5\u53E3\u8FD4\u56DE success', res.success === true, res);
  assert('\u00A72 data \u662F\u6570\u7EC4', Array.isArray(res.data), res.data);

  if (Array.isArray(res.data) && res.data.length > 0) {
    const first = res.data[0];
    assert('\u00A72 \u6A21\u677F\u542B id (number)', typeof first.id === 'number', first.id);
    assert('\u00A72 \u6A21\u677F\u542B name (string)', typeof first.name === 'string', first.name);
    assert('\u00A72 \u6A21\u677F\u542B groupId (number)', typeof first.groupId === 'number', first.groupId);
    assert('\u00A72 \u6A21\u677F\u542B sortOrder (number)', typeof first.sortOrder === 'number', first.sortOrder);
    assert('\u00A72 groupId \u4E0E\u8BF7\u6C42\u4E00\u81F4', first.groupId === testGroupId, first.groupId);
  }
}

// §3. 分组排序接口 - 正常流程
async function test_§3_sortGroups_normal() {
  console.log('\n\u2B50 \u00A73. \u5206\u7EC4\u6392\u5E8F - \u6B63\u5E38\u6D41\u7A0B');

  // 先获取当前所有分组
  const listRes = await POST('/template-group/list', {});
  if (!Array.isArray(listRes.data) || listRes.data.length < 2) {
    console.log('  \u26A0\uFE0F \u5206\u7EC4\u4E0D\u8DB3 2 \u4E2A\uFF0C\u8DF3\u8FC7\u6392\u5E8F\u6D4B\u8BD5');
    return;
  }

  const ids = listRes.data.map(g => g.id);
  const reversedIds = [...ids].reverse();

  // 排序：反转顺序
  const sortRes = await POST('/template-group/sort', { ids: reversedIds });
  assert('\u00A73 \u5206\u7EC4\u6392\u5E8F\u8FD4\u56DE success', sortRes.success === true, sortRes);

  // 验证排序生效
  const afterList = await POST('/template-group/list', {});
  assert('\u00A73 \u6392\u5E8F\u540E\u5217\u8868 success', afterList.success === true);
  const afterIds = afterList.data.map(g => g.id);
  assert('\u00A73 \u6392\u5E8F\u540E\u987A\u5E8F\u4E0E\u63D0\u4EA4\u4E00\u81F4', JSON.stringify(afterIds) === JSON.stringify(reversedIds),
    { expected: reversedIds, actual: afterIds });

  // 验证 sortOrder 值递增
  let sortOrderCorrect = true;
  for (let i = 0; i < afterList.data.length; i++) {
    if (afterList.data[i].sortOrder !== i) {
      sortOrderCorrect = false;
      break;
    }
  }
  assert('\u00A73 sortOrder \u503C\u4E3A 0,1,2,...', sortOrderCorrect);

  // 还原顺序
  await POST('/template-group/sort', { ids });
  console.log('  \u2139\uFE0F \u5DF2\u8FD8\u539F\u539F\u59CB\u987A\u5E8F');
}

// §4. 模板排序接口 - 正常流程
async function test_§4_sortTemplates_normal() {
  console.log('\n\u2B50 \u00A74. \u6A21\u677F\u6392\u5E8F - \u6B63\u5E38\u6D41\u7A0B');

  if (!testGroupId || testTemplateIds.length < 2) {
    console.log('  \u26A0\uFE0F \u6D4B\u8BD5\u6570\u636E\u4E0D\u8DB3\uFF0C\u8DF3\u8FC7');
    return;
  }

  const reversedIds = [...testTemplateIds].reverse();

  // 排序
  const sortRes = await POST('/template/sort', { groupId: testGroupId, ids: reversedIds });
  assert('\u00A74 \u6A21\u677F\u6392\u5E8F\u8FD4\u56DE success', sortRes.success === true, sortRes);

  // 验证排序生效
  const afterList = await POST('/template/listByGroupId', { groupId: testGroupId });
  assert('\u00A74 \u6392\u5E8F\u540E\u5217\u8868 success', afterList.success === true);
  const afterIds = afterList.data.map(t => t.id);
  assert('\u00A74 \u6392\u5E8F\u540E\u987A\u5E8F\u4E0E\u63D0\u4EA4\u4E00\u81F4', JSON.stringify(afterIds) === JSON.stringify(reversedIds),
    { expected: reversedIds, actual: afterIds });

  // 还原
  await POST('/template/sort', { groupId: testGroupId, ids: testTemplateIds });
  console.log('  \u2139\uFE0F \u5DF2\u8FD8\u539F\u539F\u59CB\u987A\u5E8F');
}

// §5. 分组排序 - 参数校验
async function test_§5_sortGroups_validation() {
  console.log('\n\uD83D\uDD12 \u00A75. \u5206\u7EC4\u6392\u5E8F - \u53C2\u6570\u6821\u9A8C');

  // ids 为空
  const r1 = await POST('/template-group/sort', { ids: [] });
  assert('\u00A75 ids=[] \u8FD4\u56DE\u5931\u8D25', r1.success === false, r1);

  // ids 为 null
  const r2 = await POST('/template-group/sort', {});
  assert('\u00A75 \u7F3A\u5C11 ids \u8FD4\u56DE\u5931\u8D25', r2.success === false, r2);

  // ids 包含不存在的 ID
  const r3 = await POST('/template-group/sort', { ids: [999999999] });
  assert('\u00A75 \u4E0D\u5B58\u5728\u7684 ID \u8FD4\u56DE\u5931\u8D25', r3.success === false, r3);
  assert('\u00A75 \u9519\u8BEF\u4FE1\u606F\u975E\u7A7A', r3.message != null, r3.message);
}

// §6. 模板排序 - 参数校验
async function test_§6_sortTemplates_validation() {
  console.log('\n\uD83D\uDD12 \u00A76. \u6A21\u677F\u6392\u5E8F - \u53C2\u6570\u6821\u9A8C');

  // ids 为空
  const r1 = await POST('/template/sort', { groupId: testGroupId || 1, ids: [] });
  assert('\u00A76 ids=[] \u8FD4\u56DE\u5931\u8D25', r1.success === false, r1);

  // 缺少 ids
  const r2 = await POST('/template/sort', { groupId: testGroupId || 1 });
  assert('\u00A76 \u7F3A\u5C11 ids \u8FD4\u56DE\u5931\u8D25', r2.success === false, r2);

  // groupId <= 0
  const r3 = await POST('/template/sort', { groupId: 0, ids: [1] });
  assert('\u00A76 groupId=0 \u8FD4\u56DE\u5931\u8D25', r3.success === false, r3);

  const r4 = await POST('/template/sort', { groupId: -1, ids: [1] });
  assert('\u00A76 groupId=-1 \u8FD4\u56DE\u5931\u8D25', r4.success === false, r4);

  // groupId 不存在
  const r5 = await POST('/template/sort', { groupId: 999999999, ids: [1] });
  assert('\u00A76 \u4E0D\u5B58\u5728\u7684 groupId \u8FD4\u56DE\u5931\u8D25', r5.success === false, r5);

  // 模板不属于该分组（跨组）
  if (testGroupId && testTemplateIds.length > 0) {
    // 创建另一个分组，用当前分组的模板 ID 去排序
    const otherGroup = await POST('/template-group/create', { name: 'TEST_OTHER_GROUP_' + Date.now() });
    if (otherGroup.success && otherGroup.data?.id) {
      const r6 = await POST('/template/sort', { groupId: otherGroup.data.id, ids: testTemplateIds });
      assert('\u00A76 \u8DE8\u7EC4\u6A21\u677F ID \u8FD4\u56DE\u5931\u8D25', r6.success === false, r6);
      // 清理
      await POST('/template-group/delete', { id: otherGroup.data.id });
    }
  }
}

// §7. 注入防护
async function test_§7_injection() {
  console.log('\n\uD83D\uDEE1\uFE0F \u00A77. \u6CE8\u5165\u9632\u62A4');

  // ids 传非数字
  const r1 = await POST('/template-group/sort', { ids: ["' OR 1=1 --", "1; DROP TABLE"] });
  assert('\u00A77 SQL\u6CE8\u5165\u5B57\u7B26\u4E32 ids \u4E0D\u62A5 500', r1.success === false || r1.code !== 500, r1);

  // groupId 传字符串
  const r2 = await POST('/template/sort', { groupId: "' OR 1=1", ids: [1] });
  assert('\u00A77 groupId \u6CE8\u5165\u4E0D\u62A5 500', r2.success === false || r2.code !== 500, r2);

  // 超大数组
  const bigIds = Array.from({ length: 201 }, (_, i) => i + 1);
  const r3 = await POST('/template-group/sort', { ids: bigIds });
  assert('\u00A77 ids \u8D85 200 \u4E2A\u8FD4\u56DE\u5931\u8D25', r3.success === false, r3);

  const r4 = await POST('/template/sort', { groupId: testGroupId || 1, ids: bigIds });
  assert('\u00A77 \u6A21\u677F ids \u8D85 200 \u4E2A\u8FD4\u56DE\u5931\u8D25', r4.success === false, r4);
}

// §8. 幂等性
async function test_§8_idempotent() {
  console.log('\n\uD83D\uDD01 \u00A78. \u5E42\u7B49\u6027\u6D4B\u8BD5');

  if (!testGroupId || testTemplateIds.length < 2) {
    console.log('  \u26A0\uFE0F \u6D4B\u8BD5\u6570\u636E\u4E0D\u8DB3\uFF0C\u8DF3\u8FC7');
    return;
  }

  const ids = [...testTemplateIds];

  // 同样的排序执行两次
  const r1 = await POST('/template/sort', { groupId: testGroupId, ids });
  assert('\u00A78 \u7B2C\u4E00\u6B21\u6392\u5E8F success', r1.success === true);

  const r2 = await POST('/template/sort', { groupId: testGroupId, ids });
  assert('\u00A78 \u7B2C\u4E8C\u6B21\u76F8\u540C\u6392\u5E8F success', r2.success === true);

  // 验证结果一致
  const list = await POST('/template/listByGroupId', { groupId: testGroupId });
  const afterIds = list.data.map(t => t.id);
  assert('\u00A78 \u4E24\u6B21\u6392\u5E8F\u540E\u7ED3\u679C\u4E00\u81F4', JSON.stringify(afterIds) === JSON.stringify(ids));
}

// §9. 并发请求
async function test_§9_concurrency() {
  console.log('\n\uD83D\uDD00 \u00A79. \u5E76\u53D1\u8BF7\u6C42');

  // 5 个并发 list 请求
  const promises = Array.from({ length: 5 }, () =>
    POST('/template-group/list', {})
  );
  const results = await Promise.all(promises);
  const allOk = results.every(r => r.success === true);
  assert('\u00A79 5\u4E2A\u5E76\u53D1 list \u90FD\u6210\u529F', allOk);

  // 验证返回数据一致
  if (allOk) {
    const totals = results.map(r => r.data.length);
    const allSame = totals.every(t => t === totals[0]);
    assert('\u00A79 \u5E76\u53D1\u8FD4\u56DE\u6570\u636E\u91CF\u4E00\u81F4', allSame, totals);
  }
}

// §10. 响应结构一致性
async function test_§10_responseStructure() {
  console.log('\n\uD83D\uDCE6 \u00A710. \u54CD\u5E94\u7ED3\u6784\u4E00\u81F4\u6027');

  // 所有接口都应返回 { success, code, data } 结构
  const endpoints = [
    { name: '/template-group/list', body: {} },
    { name: '/template/listByGroupId', body: { groupId: testGroupId || 1 } },
  ];

  for (const ep of endpoints) {
    const res = await POST(ep.name, ep.body);
    assert(`\u00A710 ${ep.name} \u542B success`, 'success' in res, res);
    assert(`\u00A710 ${ep.name} \u542B code`, 'code' in res, res);
    assert(`\u00A710 ${ep.name} \u542B data`, 'data' in res, res);
  }

  // 排序接口成功时返回 { success: true } 在 data 里
  if (testGroupId && testTemplateIds.length > 0) {
    const sortRes = await POST('/template/sort', { groupId: testGroupId, ids: testTemplateIds });
    assert('\u00A710 sort \u8FD4\u56DE\u5305\u542B success \u5B57\u6BB5', sortRes.success === true);
    assert('\u00A710 sort data \u5305\u542B success=true', sortRes.data?.success === true, sortRes.data);
  }
}

// ========== 执行 ==========
async function main() {
  console.log('\uD83D\uDE80 \u6A21\u677F\u6392\u5E8F\u529F\u80FD - \u63A5\u53E3\u6D4B\u8BD5');
