  console.log('  \u00A72. \u6A21\u677F\u5217\u8868\u67E5\u8BE2\uFF08\u5E26\u6392\u5E8F\uFF09');
  console.log('  \u00A73. \u5206\u7EC4\u6392\u5E8F - \u6B63\u5E38\u6D41\u7A0B + \u5199\u64CD\u4F5C\u95ED\u73AF');
