  console.log('  \u00A76. \u6A21\u677F\u6392\u5E8F - \u53C2\u6570\u6821\u9A8C\uFF08\u542B\u8DE8\u7EC4\u6821\u9A8C\uFF09');
  console.log('  \u00A77. \u6CE8\u5165\u9632\u62A4 + \u6279\u91CF\u4E0A\u9650');
  console.log('  \u00A78. \u5E42\u7B49\u6027\u6D4B\u8BD5');
