package com.yottastudios.jira.mapper;

import com.atlassian.activeobjects.external.ActiveObjects;
import com.atlassian.plugin.spring.scanner.annotation.imports.ComponentImport;
import com.yottastudios.jira.ao.Template;
import net.java.ao.DBParam;
import net.java.ao.Query;

import javax.inject.Inject;
import javax.inject.Named;
import java.util.List;

@Named
public class TemplateMapper {
    @ComponentImport
    private final ActiveObjects ao;
    private final SequenceGeneratorMapper sequenceMapper;

    @Inject
    public TemplateMapper(ActiveObjects ao, SequenceGeneratorMapper sequenceMapper) {
        this.ao = ao;
        this.sequenceMapper = sequenceMapper;
    }

    public Template create(String projectKey, String name, int groupId) {
        int nextId = sequenceMapper.getNextId();
        return ao.create(Template.class,
                new DBParam("ID", nextId),
                new DBParam("PROJECT_KEY", projectKey),
                new DBParam("NAME", name),
                new DBParam("GROUP_ID", groupId));
    }

    public Template update(int id, String name, String projectKey) {
        Template t = ao.get(Template.class, id);
        if (t == null) return null;
        t.setName(name);
        if (projectKey != null) {
            t.setProjectKey(projectKey);
        }
        t.save();
        return t;
    }

    public boolean deleteById(int id) {
        Template t = ao.get(Template.class, id);
        if (t == null) return false;
        ao.delete(t);
        return true;
    }

    public Template[] listByGroupId(int groupId) {
        return ao.find(Template.class, Query.select().where("GROUP_ID = ?", groupId).order("SORT_ORDER ASC, ID ASC"));
    }

    /**
     * 批量更新组内模板排序值：按 ids 列表顺序，依次设置 SORT_ORDER = 0, 1, 2, ...
     * 校验所有 id 必须属于指定 groupId
     */
    public void batchUpdateSortOrder(int groupId, List<Integer> ids) {
        ao.executeInTransaction(() -> {
            for (int i = 0; i < ids.size(); i++) {
                Template t = ao.get(Template.class, ids.get(i));
                if (t == null) {
                    throw new RuntimeException("模板不存在, id=" + ids.get(i));
                }
                if (t.getGroupId() != groupId) {
                    throw new RuntimeException("模板id=" + ids.get(i) + "不属于分组groupId=" + groupId);
                }
                t.setSortOrder(i);
                t.save();
            }
            return null;
        });
    }

    public Template getById(int id) {
        return ao.get(Template.class, id);
    }
}

