   1→# JS 接口测试生成
   2→
   3→用 Node.js 原生 fetch 生成 Web 接口的全覆盖自动化测试脚本，360 度无死角。
   4→
   5→## 参数
   6→
   7→$ARGUMENTS — 接口文档路径、Controller 代码路径、API 前缀、或需要测试的功能描述
   8→
   9→## 适用场景
  10→
  11→- 后端接口开发完成后的验收测试
  12→- 测试环境部署后的冒烟测试
  13→- 接口重构后的回归测试
  14→- 新功能上线前的全量接口验证
  15→
  16→## 硬性指标（不满足就不算完成）
  17→
  18→1. **每个接口至少 5 个 assert**：正常返回结构 + 至少 1 个字段类型校验 + 至少 1 个参数校验 + 至少 1 个异常数据 + 至少 1 个注入/特殊字符
  19→2. **多账号测试不可跳过**：必须测至少 2 种权限级别（管理员 + 普通用户），有权限校验的写接口必须验证普通用户被拒绝
  20→3. **覆盖矩阵必须输出**：生成完成后必须输出「13 维度 × N 接口」覆盖表，每格标注 ✅（已覆盖）/ ❌（未覆盖，需补）/ N/A（不适用+原因）
  21→4. **最低 assert 总数 = 接口数 × 8**：例如 15 个接口至少 120 个 assert。不足必须补
  22→5. **所有写操作必须有清理/还原逻辑**：测试结束后数据状态不应比开始时更脏
  23→
  24→## 执行步骤
  25→
  26→### 第一步：收集信息
  27→
  28→1. **读功能点对照文档**（`myfeature/` 目录下的 `*功能点对照*.md`），提取所有功能点编号和描述
  29→   - 如果没有功能点对照文档，先用 `/lbl-04-feature-mapping` 生成
  30→   - 记录每个功能点的编号（如 `§1.创建公告`）、说明、关键代码位置
  31→   - 这是测试用例组织的**核心依据**：每个测试函数/assert 必须标注对应的功能点
  32→2. **读接口文档**（md / swagger / 代码注释），提取**所有**接口路径、方法、参数、返回值
  33→   - 特别注意：单个/批量版本必须都列出（如 editRole / batchEditRole、deleteRole / batchDeleteRole）
  34→3. **读 Controller 代码**，确认：
  35→   - 权限注解（哪些接口需要登录、需要什么角色）
  36→   - 参数校验注解（@Valid、@NotNull、@NotEmpty、@Min、@Max）—— 特别关注**列表参数是否校验了空列表**
  37→   - 返回值类型和结构
  38→   - **权限校验异常是否被统一异常处理器正确映射**（是返回 403 还是 500？）
  39→4. **读 Service/Manager 实现代码**，重点关注：
  40→   - 写操作的 upsert 逻辑是否真的能 update（MyBatis-Plus `saveOrUpdateBatch` 基于主键，不基于业务唯一键）
  41→   - 同类接口的逻辑对称性（如 listA 考虑继承但 listB 不考虑）
  42→   - 内存去重（`Collectors.toMap(..., (a,b)->a)`）是否掩盖了 DB 层重复数据
  43→5. **查数据库**找测试数据 + 检查数据质量：
  44→   - 目标资源的 ID（空间 ID、节点 ID、文档 ID 等）
  45→   - 所有相关用户及其角色（owner / admin / manager / editor / reader / 外部 / 系统）
  46→   - 用 `SELECT` 确认数据存在，不要假设
  47→   - **查重复数据**：`SELECT count(*), col1, col2 FROM table GROUP BY col1, col2 HAVING count(*) > 1`
  48→   - **查唯一索引**：`SELECT INDEX_NAME, COLUMN_NAME, NON_UNIQUE FROM information_schema.STATISTICS WHERE TABLE_NAME = 'xxx'`
  49→6. **确认认证机制**：
  50→   - 测试登录入口（testLogin 接口 / 测试 token / OAuth mock）
  51→   - CSRF 机制（XSRF-TOKEN cookie 需同时作为 header 发送）
  52→   - Session 机制（cookie 名称、过期策略）
  53→7. **确认测试环境地址**和端口
  54→
  55→### 第二步：生成测试脚本
  56→
  57→生成 `05-test-api.js`，文件结构固定如下：
  58→
  59→```javascript
  60→/**
  61→ * [功能名称] - 接口测试脚本
  62→ *
  63→ * 用法: node 05-test-api.js
  64→ * 要求: Node.js 18+（原生 fetch）
  65→ * 自动登录测试环境，无需手动填 Cookie
  66→ */
  67→
  68→// ========== 配置 ==========
  69→const CONFIG = {
  70→  host: 'http://xxx-test.example.com',
  71→  loginEmail: 'test@example.com',
  72→  // ... 业务相关的 ID
  73→};
  74→
  75→// ========== 测试框架 ==========
  76→let passed = 0;
  77→let failed = 0;
  78→let cookie = '';
  79→let xsrfToken = '';
  80→
  81→function assert(name, condition, detail) {
  82→  if (condition) {
  83→    console.log(`  ✅ ${name}`);
  84→    passed++;
  85→  } else {
  86→    console.log(`  ❌ ${name}`);
  87→    if (detail !== undefined)
  88→      console.log(`     实际值:`, typeof detail === 'object'
  89→        ? JSON.stringify(detail).slice(0, 200) : detail);
  90→    failed++;
  91→  }
  92→}
  93→
  94→// ========== HTTP 工具 ==========
  95→
  96→/** 从 set-cookie 头中提取 cookie 值 */
  97→function parseCookies(res) {
  98→  const cookies = {};
  99→  const setCookieHeaders = res.headers.getSetCookie?.() || [];
 100→  for (const header of setCookieHeaders) {
 101→    const [kv] = header.split(';');
 102→    const [k, v] = kv.split('=');
 103→    cookies[k.trim()] = v.trim();
 104→  }
 105→  return cookies;
 106→}
 107→
 108→async function rawFetch(method, url, body) {
 109→  const headers = {
 110→    'x-space-id': CONFIG.spaceId,      // 按项目实际 header 调整
 111→    'content-type': 'application/json',
 112→  };
 113→  if (cookie) headers['cookie'] = cookie;
 114→  if (xsrfToken) headers['x-xsrf-token'] = xsrfToken;
 115→
 116→  const opts = { method, headers, redirect: 'manual' };
 117→  if (body) opts.body = JSON.stringify(body);
 118→  return fetch(url, opts);
 119→}
 120→
 121→async function GET(path) {
 122→  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
 123→  return res.json();
 124→}
 125→
 126→async function POST(path, body) {
 127→  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body);
 128→  return res.json();
 129→}
 130→
 131→// ========== 登录管理 ==========
 132→
 133→async function login() {
 134→  console.log(`🔑 登录 ${CONFIG.loginEmail} ...`);
 135→  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${CONFIG.loginEmail}`,
 136→    { redirect: 'manual' });
 137→  const cookies = parseCookies(res);
 138→  if (!cookies.SESSION) {
 139→    console.log('❌ 登录失败');
 140→    process.exit(1);
 141→  }
 142→  xsrfToken = cookies['XSRF-TOKEN'] || '';
 143→  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
 144→  console.log(`   ✅ 登录成功\n`);
 145→}
 146→
 147→let savedSessions = {};
 148→function saveSession(name) {
 149→  savedSessions[name] = { cookie, xsrfToken };
 150→}
 151→function restoreSession(name) {
 152→  ({ cookie, xsrfToken } = savedSessions[name]);
 153→}
 154→
 155→async function loginAs(email) {
 156→  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${email}`,
 157→    { redirect: 'manual' });
 158→  const cookies = parseCookies(res);
 159→  if (!cookies.SESSION) {
 160→    console.log(`  ⚠️  登录 ${email} 失败，跳过`);
 161→    return false;
 162→  }
 163→  xsrfToken = cookies['XSRF-TOKEN'] || '';
 164→  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
 165→  return true;
 166→}
 167→
 168→// ========== 测试用例 ==========
 169→// 每组一个 async function，按维度组织
 170→
 171→// ========== 执行 ==========
 172→async function main() {
 173→  console.log('🚀 [功能名称] - 接口测试');
 174→  try {
 175→    await login();
 176→    // await testXxx(); ...
 177→  } catch (e) {
 178→    if (e.cause?.code === 'ECONNREFUSED') {
 179→      console.log('\n❌ 无法连接测试环境，请检查网络');
 180→    } else {
 181→      console.log(`\n❌ 异常: ${e.stack || e.message}`);
 182→    }
 183→    process.exit(1);
 184→  }
 185→  console.log(`\n=============================`);
 186→  console.log(`✅ 通过: ${passed}  ❌ 失败: ${failed}  📊 总计: ${passed + failed}`);
 187→  console.log(`=============================`);
 188→  process.exit(failed > 0 ? 1 : 0);
 189→}
 190→main();
 191→```
