 271→#### 维度 2：分页边界
 272→```javascript
 273→async function testPaginationBoundary() {
 274→  console.log('\n📐 分页边界');
 275→
 276→  // 最小 pageSize
 277→  const p1 = await GET('/listXxx?pageNo=1&pageSize=1');
 278→  assert('pageSize=1 最多返回1条', p1.data?.records?.length <= 1);
 279→
 280→  // 最大合法 pageSize
 281→  const p100 = await GET('/listXxx?pageNo=1&pageSize=100');
 282→  assert('pageSize=100 返回成功', p100.success === true);
 283→
 284→  // total 与 records 一致性
 285→  if (p100.data?.total <= 100) {
 286→    assert('total <= 100 时 length === total',
 287→      p100.data.records.length === p100.data.total);
 288→  }
 289→
 290→  // 超出最后一页
 291→  const overPage = await GET('/listXxx?pageNo=9999&pageSize=20');
 292→  assert('超页返回空列表', overPage.data?.records?.length === 0);
 293→  assert('超页 total 不变', overPage.data?.total === p100.data?.total);
 294→
 295→  // 两页不重复
 296→  if (p1.data?.total > 1) {
 297→    const p2 = await GET('/listXxx?pageNo=2&pageSize=1');
 298→    assert('第2页有数据', p2.data?.records?.length > 0);
 299→    assert('两页 ID 不重复',
 300→      p1.data.records[0].id !== p2.data.records[0].id);
 301→  }
 302→
 303→  // 不传分页参数用默认值
 304→  const noPage = await GET('/listXxx');
 305→  assert('不传分页参数用默认值', noPage.success === true);
 306→  assert('默认 records 不超过 20', noPage.data?.records?.length <= 20);
 307→}
