 310→#### 维度 3：搜索边界
 311→```javascript
 312→async function testSearchBoundary() {
 313→  console.log('\n🔎 搜索边界');
 314→
 315→  // 先拿一条真实数据
 316→  const all = await GET('/listXxx?pageNo=1&pageSize=100');
 317→  if (all.data?.records?.length > 0) {
 318→    const realName = all.data.records[0].name;
 319→
 320→    // 精确匹配
 321→    const exact = await GET(`/listXxx?keyword=${encodeURIComponent(realName)}&pageNo=1&pageSize=20`);
 322→    assert(`精确搜索"${realName}"有结果`, exact.data?.records?.length > 0);
 323→
 324→    // 部分匹配
 325→    if (realName.length > 1) {
 326→      const partial = realName.substring(0, 1);
 327→      const partialRes = await GET(`/listXxx?keyword=${encodeURIComponent(partial)}&pageNo=1&pageSize=20`);
 328→      assert(`部分匹配"${partial}"有结果`, partialRes.data?.records?.length > 0);
 329→    }
 330→
 331→    // 大小写不敏感（如有英文）
 332→    if (/[a-zA-Z]/.test(realName)) {
 333→      const upper = await GET(`/listXxx?keyword=${encodeURIComponent(realName.toUpperCase())}&pageNo=1&pageSize=20`);
 334→      const lower = await GET(`/listXxx?keyword=${encodeURIComponent(realName.toLowerCase())}&pageNo=1&pageSize=20`);
 335→      assert('搜索大小写不敏感', upper.data?.total === lower.data?.total);
 336→    }
 337→  }
 338→
 339→  // 空 keyword 等同不传
 340→  const noKw = await GET('/listXxx?pageNo=1&pageSize=20');
 341→  const emptyKw = await GET('/listXxx?keyword=&pageNo=1&pageSize=20');
 342→  assert('空 keyword 等同不传', emptyKw.data?.total === noKw.data?.total);
 343→
 344→  // 纯空格
 345→  const spaceKw = await GET(`/listXxx?keyword=${encodeURIComponent('   ')}&pageNo=1&pageSize=20`);
 346→  assert('纯空格 keyword 不报错', spaceKw.success === true);
 347→
 348→  // 不存在
 349→  const none = await GET(`/listXxx?keyword=${encodeURIComponent('不存在的xxx')}&pageNo=1&pageSize=20`);
 350→  assert('不存在关键词返回空', none.data?.records?.length === 0);
 351→
 352→  // 搜索 + 分页 total 一致
 353→  if (all.data?.records?.length > 0) {
 354→    const kw = all.data.records[0].name;
 355→    const s1 = await GET(`/listXxx?keyword=${encodeURIComponent(kw)}&pageNo=1&pageSize=1`);
 356→    const s2 = await GET(`/listXxx?keyword=${encodeURIComponent(kw)}&pageNo=1&pageSize=100`);
 357→    assert('搜索不同 pageSize 下 total 一致', s1.data?.total === s2.data?.total);
